const securityScriptingFundamentalsHtml = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>SCRIPT//SEC — Security Scripting Fundamentals</title>\n<style>\n@import url('https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@300;400;600;700&family=Syne:wght@400;700;800&family=DM+Sans:wght@300;400;500&display=swap');\n\n:root {\n  --bg0: #03070d;\n  --bg1: #060d18;\n  --bg2: #0a1525;\n  --bg3: #0f1e35;\n  --bg4: #162844;\n\n  --green:  #39ff7e;\n  --green2: #1adf5c;\n  --cyan:   #00cfff;\n  --cyan2:  #0099cc;\n  --yellow: #ffe04b;\n  --orange: #ff8c42;\n  --red:    #ff3d5a;\n  --purple: #b06aff;\n  --pink:   #ff5fa0;\n\n  --text:   #cce0ff;\n  --dim:    #4a6a90;\n  --muted:  #1e3050;\n\n  --mono: 'JetBrains Mono', monospace;\n  --sans: 'DM Sans', sans-serif;\n  --display: 'Syne', sans-serif;\n\n  --r: 3px;\n}\n\n*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }\n\nhtml { scroll-behavior: smooth; }\n\nbody {\n  background: var(--bg0);\n  color: var(--text);\n  font-family: var(--sans);\n  min-height: 100vh;\n  overflow-x: hidden;\n}\n\n/* ── GRID NOISE OVERLAY ── */\nbody::after {\n  content: '';\n  position: fixed; inset: 0;\n  background-image:\n    linear-gradient(rgba(0,207,255,.02) 1px, transparent 1px),\n    linear-gradient(90deg, rgba(0,207,255,.02) 1px, transparent 1px);\n  background-size: 40px 40px;\n  pointer-events: none;\n  z-index: 0;\n}\n\n/* ── GLOW ORBS ── */\n.orb {\n  position: fixed;\n  border-radius: 50%;\n  filter: blur(120px);\n  opacity: .12;\n  pointer-events: none;\n  z-index: 0;\n}\n.orb-1 { width: 500px; height: 500px; background: var(--cyan);  top: -200px; right: -100px; }\n.orb-2 { width: 400px; height: 400px; background: var(--green); bottom: 100px; left: -100px; }\n\n.z1 { position: relative; z-index: 1; }\n\n/* ══ TOP NAV ══ */\nnav {\n  position: sticky; top: 0; z-index: 200;\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 0 32px;\n  height: 56px;\n  background: rgba(3,7,13,.85);\n  backdrop-filter: blur(20px);\n  border-bottom: 1px solid rgba(0,207,255,.08);\n}\n\n.nav-brand {\n  font-family: var(--mono);\n  font-size: .75rem;\n  font-weight: 700;\n  color: var(--cyan);\n  letter-spacing: 3px;\n  text-transform: uppercase;\n}\n.nav-brand span { color: var(--green); }\n\n.nav-pills {\n  display: flex; gap: 4px;\n}\n.nav-pill {\n  font-family: var(--mono);\n  font-size: .62rem;\n  letter-spacing: 1.5px;\n  text-transform: uppercase;\n  padding: 5px 14px;\n  border-radius: 2px;\n  cursor: pointer;\n  color: var(--dim);\n  background: transparent;\n  border: none;\n  transition: all .2s;\n}\n.nav-pill:hover { color: var(--text); }\n.nav-pill.active {\n  color: var(--bg0);\n  font-weight: 700;\n}\n.nav-pill.bash.active  { background: var(--green); }\n.nav-pill.python.active { background: var(--cyan); }\n.nav-pill.pwsh.active  { background: var(--purple); }\n.nav-pill.secure.active { background: var(--orange); }\n.nav-pill.ir.active    { background: var(--red); }\n\n/* ══ HERO STRIP ══ */\n.hero {\n  padding: 64px 40px 48px;\n  position: relative;\n  overflow: hidden;\n}\n\n.hero-eyebrow {\n  font-family: var(--mono);\n  font-size: .65rem;\n  letter-spacing: 5px;\n  color: var(--green);\n  text-transform: uppercase;\n  margin-bottom: 16px;\n  opacity: .8;\n}\n\n.hero-title {\n  font-family: var(--display);\n  font-size: clamp(2.2rem, 5vw, 4rem);\n  font-weight: 800;\n  line-height: 1.05;\n  letter-spacing: -1px;\n  margin-bottom: 16px;\n}\n.hero-title .t-bash   { color: var(--green); }\n.hero-title .t-py     { color: var(--cyan); }\n.hero-title .t-ps     { color: var(--purple); }\n\n.hero-sub {\n  font-size: 1rem;\n  color: var(--dim);\n  font-weight: 300;\n  max-width: 560px;\n  line-height: 1.7;\n  margin-bottom: 32px;\n}\n\n/* Stat chips */\n.stat-row { display: flex; gap: 12px; flex-wrap: wrap; }\n.stat-chip {\n  font-family: var(--mono);\n  font-size: .68rem;\n  padding: 6px 14px;\n  border-radius: var(--r);\n  letter-spacing: 1px;\n  border: 1px solid;\n}\n.sc-g { color: var(--green);  border-color: rgba(57,255,126,.2); background: rgba(57,255,126,.05); }\n.sc-c { color: var(--cyan);   border-color: rgba(0,207,255,.2);  background: rgba(0,207,255,.05); }\n.sc-p { color: var(--purple); border-color: rgba(176,106,255,.2);background: rgba(176,106,255,.05); }\n.sc-o { color: var(--orange); border-color: rgba(255,140,66,.2); background: rgba(255,140,66,.05); }\n\n/* ══ SECTION WRAPPER ══ */\n.module { display: none; }\n.module.active { display: block; }\n\n.wrapper {\n  max-width: 1200px;\n  margin: 0 auto;\n  padding: 0 40px 80px;\n}\n\n/* ══ SECTION HEADING ══ */\n.sh {\n  display: flex; align-items: flex-start; gap: 20px;\n  margin-bottom: 36px;\n  padding-bottom: 24px;\n  border-bottom: 1px solid rgba(0,207,255,.07);\n}\n.sh-num {\n  font-family: var(--mono);\n  font-size: 3.5rem;\n  font-weight: 700;\n  line-height: 1;\n  color: var(--muted);\n  flex-shrink: 0;\n  user-select: none;\n}\n.sh-body {}\n.sh-tag {\n  font-family: var(--mono);\n  font-size: .6rem;\n  letter-spacing: 4px;\n  text-transform: uppercase;\n  color: var(--dim);\n  margin-bottom: 6px;\n}\n.sh-title {\n  font-family: var(--display);\n  font-size: 1.7rem;\n  font-weight: 800;\n  line-height: 1.1;\n  margin-bottom: 6px;\n}\n.sh-desc { font-size: .93rem; color: var(--dim); font-weight: 300; line-height: 1.6; }\n\n/* ══ LAYOUT GRIDS ══ */\n.g2 { display: grid; grid-template-columns: repeat(2,1fr); gap: 16px; }\n.g3 { display: grid; grid-template-columns: repeat(3,1fr); gap: 16px; }\n.g-asymm { display: grid; grid-template-columns: 1.4fr 1fr; gap: 16px; }\n@media(max-width:900px){ .g2,.g3,.g-asymm { grid-template-columns:1fr; } }\n\n/* ══ CARDS ══ */\n.card {\n  background: var(--bg1);\n  border: 1px solid rgba(255,255,255,.05);\n  border-radius: var(--r);\n  padding: 24px;\n  position: relative;\n  overflow: hidden;\n  transition: border-color .25s, transform .2s;\n}\n.card:hover { transform: translateY(-2px); border-color: rgba(0,207,255,.15); }\n.card::before {\n  content:'';\n  position:absolute;\n  top:0;left:0;right:0;\n  height:2px;\n  background: var(--card-accent, transparent);\n  opacity: 0;\n  transition: opacity .3s;\n}\n.card:hover::before { opacity: 1; }\n\n/* accent variants */\n.ca-g  { --card-accent: linear-gradient(90deg,var(--green),transparent); }\n.ca-c  { --card-accent: linear-gradient(90deg,var(--cyan),transparent); }\n.ca-p  { --card-accent: linear-gradient(90deg,var(--purple),transparent); }\n.ca-o  { --card-accent: linear-gradient(90deg,var(--orange),transparent); }\n.ca-r  { --card-accent: linear-gradient(90deg,var(--red),transparent); }\n\n.card-label {\n  font-family: var(--mono);\n  font-size: .58rem;\n  letter-spacing: 3px;\n  text-transform: uppercase;\n  color: var(--dim);\n  margin-bottom: 10px;\n}\n.card-title {\n  font-family: var(--display);\n  font-size: 1rem;\n  font-weight: 700;\n  margin-bottom: 10px;\n  letter-spacing: -.3px;\n}\n.card-body {\n  font-size: .88rem;\n  color: var(--dim);\n  line-height: 1.7;\n  font-weight: 300;\n}\n.card-body strong { color: var(--text); font-weight: 500; }\n.card-body code {\n  font-family: var(--mono);\n  font-size: .78rem;\n  color: var(--green);\n  background: rgba(57,255,126,.07);\n  padding: 1px 5px;\n  border-radius: 2px;\n}\n\n/* ══ CODE PANES ══ */\n.code-pane {\n  background: #020912;\n  border: 1px solid rgba(0,207,255,.08);\n  border-radius: var(--r);\n  overflow: hidden;\n  margin: 14px 0;\n  position: relative;\n}\n.code-pane-bar {\n  display: flex; align-items: center; justify-content: space-between;\n  padding: 8px 16px;\n  background: rgba(0,207,255,.04);\n  border-bottom: 1px solid rgba(0,207,255,.07);\n}\n.code-pane-name {\n  font-family: var(--mono);\n  font-size: .62rem;\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  color: var(--dim);\n}\n.code-pane-lang {\n  font-family: var(--mono);\n  font-size: .58rem;\n  letter-spacing: 2px;\n  padding: 2px 8px;\n  border-radius: 2px;\n}\n.lang-bash   { background: rgba(57,255,126,.1);  color: var(--green);  }\n.lang-python { background: rgba(0,207,255,.1);   color: var(--cyan);   }\n.lang-pwsh   { background: rgba(176,106,255,.1); color: var(--purple); }\n.lang-text   { background: rgba(255,140,66,.1);  color: var(--orange); }\n\n.code-pane pre {\n  padding: 18px 20px;\n  font-family: var(--mono);\n  font-size: .775rem;\n  line-height: 1.85;\n  overflow-x: auto;\n  color: #7a99bb;\n}\n\n/* Syntax highlight token classes */\n.t-kw  { color: #b06aff; font-style: italic; }   /* keyword */\n.t-fn  { color: #39ff7e; }                        /* function/command */\n.t-str { color: #ffe04b; }                        /* string */\n.t-num { color: #ff8c42; }                        /* number */\n.t-cmt { color: #2a4a6a; font-style: italic; }   /* comment */\n.t-var { color: #00cfff; }                        /* variable */\n.t-op  { color: #ff5fa0; }                        /* operator/pipe */\n.t-err { color: #ff3d5a; }                        /* error/danger */\n.t-ok  { color: #39ff7e; }                        /* success */\n.t-dim { color: #2a4a6a; }                        /* dimmed */\n\n/* ══ TOPIC NAV (in-page) ══ */\n.topic-nav {\n  display: flex; gap: 6px; flex-wrap: wrap;\n  margin-bottom: 28px;\n}\n.topic-btn {\n  font-family: var(--mono);\n  font-size: .62rem;\n  letter-spacing: 1.5px;\n  text-transform: uppercase;\n  padding: 5px 12px;\n  border-radius: 2px;\n  cursor: pointer;\n  color: var(--dim);\n  background: var(--bg2);\n  border: 1px solid rgba(255,255,255,.05);\n  transition: all .18s;\n}\n.topic-btn:hover, .topic-btn.active { color: var(--bg0); }\n.topic-btn.active.bash   { background: var(--green);  border-color: var(--green); }\n.topic-btn.active.python { background: var(--cyan);   border-color: var(--cyan); }\n.topic-btn.active.pwsh   { background: var(--purple); border-color: var(--purple); }\n.topic-btn.active.secure { background: var(--orange); border-color: var(--orange); }\n\n/* ══ ALERTS ══ */\n.alert {\n  border-radius: var(--r);\n  padding: 13px 18px;\n  margin: 14px 0;\n  font-size: .86rem;\n  line-height: 1.65;\n  font-weight: 300;\n  border-left: 3px solid;\n}\n.alert strong { font-weight: 600; }\n.a-warn { background: rgba(255,140,66,.07); border-color: var(--orange); color: #ffb070; }\n.a-info { background: rgba(0,207,255,.06);  border-color: var(--cyan);   color: #80d8ff; }\n.a-ok   { background: rgba(57,255,126,.06); border-color: var(--green);  color: #80ffb0; }\n.a-err  { background: rgba(255,61,90,.07);  border-color: var(--red);    color: #ff9090; }\n\n/* ══ FEATURE GRID (checklist style) ══ */\n.feature-list { list-style: none; }\n.feature-list li {\n  display: flex; gap: 10px;\n  padding: 9px 0;\n  font-size: .88rem;\n  color: var(--dim);\n  border-bottom: 1px solid rgba(255,255,255,.03);\n  font-weight: 300;\n  line-height: 1.5;\n}\n.feature-list li:last-child { border-bottom: none; }\n.feature-list .fi { flex-shrink: 0; margin-top: 1px; }\n.feature-list strong { color: var(--text); font-weight: 500; }\n.feature-list code {\n  font-family: var(--mono);\n  font-size: .75rem;\n  color: var(--green);\n  background: rgba(57,255,126,.07);\n  padding: 1px 5px;\n  border-radius: 2px;\n}\n\n/* ══ COMPARISON TABLE ══ */\n.cmp-table { width: 100%; border-collapse: collapse; margin: 14px 0; }\n.cmp-table th {\n  font-family: var(--mono);\n  font-size: .6rem;\n  letter-spacing: 2px;\n  text-transform: uppercase;\n  color: var(--dim);\n  text-align: left;\n  padding: 10px 14px;\n  background: var(--bg2);\n  border: 1px solid rgba(255,255,255,.04);\n}\n.cmp-table td {\n  font-size: .84rem;\n  font-weight: 300;\n  padding: 10px 14px;\n  border: 1px solid rgba(255,255,255,.03);\n  vertical-align: top;\n  line-height: 1.5;\n  color: var(--dim);\n}\n.cmp-table tr:hover td { background: rgba(255,255,255,.015); }\n.cmp-table td strong { color: var(--text); font-weight: 500; }\n.cmp-table .td-g { color: var(--green); font-family: var(--mono); font-size: .78rem; font-weight: 600; }\n.cmp-table .td-c { color: var(--cyan);   font-family: var(--mono); font-size: .78rem; font-weight: 600; }\n.cmp-table .td-p { color: var(--purple); font-family: var(--mono); font-size: .78rem; font-weight: 600; }\n\n/* ══ FLOW DIAGRAM ══ */\n.flow {\n  display: flex; align-items: center; gap: 0;\n  flex-wrap: wrap;\n  margin: 20px 0;\n}\n.flow-step {\n  flex: 1; min-width: 100px;\n  padding: 16px 12px;\n  text-align: center;\n  background: var(--bg2);\n  border: 1px solid rgba(0,207,255,.08);\n  position: relative;\n}\n.flow-step::after {\n  content: '→';\n  position: absolute;\n  right: -12px; top: 50%;\n  transform: translateY(-50%);\n  color: var(--muted);\n  font-size: .8rem;\n  z-index: 2;\n}\n.flow-step:last-child::after { display: none; }\n.flow-num {\n  font-family: var(--mono);\n  font-size: .55rem; letter-spacing: 2px;\n  color: var(--muted); margin-bottom: 6px;\n}\n.flow-icon { font-size: 1.3rem; margin-bottom: 5px; }\n.flow-name { font-family: var(--mono); font-size: .65rem; color: var(--cyan); letter-spacing: 1px; margin-bottom: 3px; }\n.flow-desc { font-size: .72rem; color: var(--dim); line-height: 1.3; }\n\n/* ══ BADGE ROW ══ */\n.badge-row { display: flex; flex-wrap: wrap; gap: 6px; margin-top: 12px; }\n.badge {\n  font-family: var(--mono);\n  font-size: .6rem;\n  letter-spacing: 1px;\n  padding: 3px 9px;\n  border-radius: 2px;\n  border: 1px solid;\n  text-transform: uppercase;\n}\n.bg { color:var(--green);  border-color:rgba(57,255,126,.3);  background:rgba(57,255,126,.07); }\n.bc { color:var(--cyan);   border-color:rgba(0,207,255,.3);   background:rgba(0,207,255,.07); }\n.bp { color:var(--purple); border-color:rgba(176,106,255,.3); background:rgba(176,106,255,.07); }\n.bo { color:var(--orange); border-color:rgba(255,140,66,.3);  background:rgba(255,140,66,.07); }\n.br { color:var(--red);    border-color:rgba(255,61,90,.3);   background:rgba(255,61,90,.07); }\n\n/* ══ VULN DIFF ══ */\n.diff-block {\n  background: #020912;\n  border: 1px solid rgba(255,255,255,.05);\n  border-radius: var(--r);\n  overflow: hidden;\n  margin: 14px 0;\n}\n.diff-row {\n  display: flex;\n  font-family: var(--mono);\n  font-size: .75rem;\n  line-height: 1.7;\n}\n.diff-sign {\n  width: 32px; flex-shrink: 0;\n  display: flex; align-items: center; justify-content: center;\n  font-weight: 700;\n}\n.diff-code { flex: 1; padding: 3px 12px 3px 0; white-space: pre-wrap; word-break: break-word; }\n.diff-add { background: rgba(57,255,126,.06); }\n.diff-add .diff-sign { color: var(--green); }\n.diff-add .diff-code { color: #80ffb0; }\n.diff-rem { background: rgba(255,61,90,.06); }\n.diff-rem .diff-sign { color: var(--red); }\n.diff-rem .diff-code { color: #ff9090; }\n.diff-cmt { padding: 6px 14px; }\n.diff-cmt .diff-code { color: var(--muted); font-style: italic; }\n\n/* ══ DIVIDER ══ */\n.div-line {\n  height: 1px;\n  background: linear-gradient(90deg,transparent,rgba(0,207,255,.12),transparent);\n  margin: 28px 0;\n}\n\n/* ══ PROGRESS TRACKER ══ */\n.progress-track {\n  display: flex; flex-direction: column; gap: 10px;\n  padding: 16px;\n  background: var(--bg2);\n  border-radius: var(--r);\n  border: 1px solid rgba(255,255,255,.04);\n  margin-top: 14px;\n}\n.pt-row { display: flex; align-items: center; gap: 12px; }\n.pt-label {\n  font-family: var(--mono);\n  font-size: .65rem;\n  color: var(--dim);\n  width: 120px;\n  flex-shrink: 0;\n  letter-spacing: 1px;\n  text-transform: uppercase;\n}\n.pt-bar { flex: 1; height: 3px; background: var(--muted); border-radius: 2px; overflow: hidden; }\n.pt-fill { height: 100%; border-radius: 2px; }\n.pt-pct { font-family: var(--mono); font-size: .6rem; color: var(--muted); width: 34px; text-align: right; }\n\n/* pill navigation scrollable on mobile */\n@media(max-width:640px){\n  nav { padding: 0 16px; }\n  .nav-pills { overflow-x:auto; scrollbar-width:none; }\n  .nav-pills::-webkit-scrollbar { display:none; }\n  .wrapper { padding: 0 16px 60px; }\n  .hero { padding: 40px 16px 32px; }\n}\n</style>\n</head>\n<body>\n\n<div class=\"orb orb-1\"></div>\n<div class=\"orb orb-2\"></div>\n\n<!-- ══ NAV ══ -->\n<nav class=\"z1\">\n  <div class=\"nav-brand\">SCRIPT<span>/</span>SEC</div>\n  <div class=\"nav-pills\">\n    <button class=\"nav-pill bash active\"   onclick=\"switchModule('bash',this)\">Bash</button>\n    <button class=\"nav-pill python\"        onclick=\"switchModule('python',this)\">Python</button>\n    <button class=\"nav-pill pwsh\"          onclick=\"switchModule('pwsh',this)\">PowerShell</button>\n    <button class=\"nav-pill secure\"        onclick=\"switchModule('secure',this)\">Secure Coding</button>\n    <button class=\"nav-pill ir\"            onclick=\"switchModule('ir',this)\">IR Scripts</button>\n  </div>\n</nav>\n\n<!-- ══ HERO ══ -->\n<div class=\"hero z1\">\n  <div class=\"hero-eyebrow\">// Module 01 — Script Writing Fundamentals //</div>\n  <h1 class=\"hero-title\">\n    <span class=\"t-bash\">Bash.</span>\n    <span class=\"t-py\"> Python.</span>\n    <span class=\"t-ps\"> PowerShell.</span><br>\n    Security Scripting.\n  </h1>\n  <p class=\"hero-sub\">From log parsing and system monitoring to incident response automation. Every script written through a security lens — because the tool you write today is the target tomorrow.</p>\n  <div class=\"stat-row\">\n    <span class=\"stat-chip sc-g\">5 Modules</span>\n    <span class=\"stat-chip sc-c\">30+ Scripts</span>\n    <span class=\"stat-chip sc-p\">Secure Patterns</span>\n    <span class=\"stat-chip sc-o\">IR Playbooks</span>\n  </div>\n</div>\n\n<!-- ══════════════════════════════════\n     MODULE: BASH\n══════════════════════════════════ -->\n<div class=\"module active z1\" id=\"mod-bash\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">01</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-tag\">// Shell Scripting //</div>\n      <div class=\"sh-title\" style=\"color:var(--green)\">Bash for Security</div>\n      <div class=\"sh-desc\">The Linux security analyst's first language. Fast, composable, universally available. Master pipelines, process substitution, and real-time log analysis.</div>\n    </div>\n  </div>\n\n  <!-- Fundamentals overview -->\n  <div class=\"g3\" style=\"margin-bottom:20px\">\n    <div class=\"card ca-g\">\n      <div class=\"card-label\">Core Concept</div>\n      <div class=\"card-title\" style=\"color:var(--green)\">Why Bash First</div>\n      <div class=\"card-body\">Available on every Linux/Unix system — no interpreter install required. Ideal for <strong>log triage, rapid IR, cron-based monitoring</strong>, and chaining existing security tools. Speed &gt; elegance.</div>\n      <div class=\"badge-row\">\n        <span class=\"badge bg\">POSIX</span>\n        <span class=\"badge bg\">No Deps</span>\n        <span class=\"badge bg\">Pipeline</span>\n      </div>\n    </div>\n    <div class=\"card ca-g\">\n      <div class=\"card-label\">Key Constructs</div>\n      <div class=\"card-title\" style=\"color:var(--green)\">Security-Relevant Bash</div>\n      <ul class=\"feature-list\">\n        <li><span class=\"fi\">▸</span><div><strong>Pipelines</strong> — <code>grep | awk | sort | uniq</code> for log analysis</div></li>\n        <li><span class=\"fi\">▸</span><div><strong>Process substitution</strong> — <code>diff &lt;(cmd1) &lt;(cmd2)</code> for diffing outputs</div></li>\n        <li><span class=\"fi\">▸</span><div><strong>Here-strings</strong> — pass data without temp files</div></li>\n        <li><span class=\"fi\">▸</span><div><strong>Trap signals</strong> — cleanup on script exit or interrupt</div></li>\n      </ul>\n    </div>\n    <div class=\"card ca-g\">\n      <div class=\"card-label\">Security Use Cases</div>\n      <div class=\"card-title\" style=\"color:var(--green)\">When to Use Bash</div>\n      <ul class=\"feature-list\">\n        <li><span class=\"fi\">🔍</span><div>Real-time log tailing and alerting</div></li>\n        <li><span class=\"fi\">🔐</span><div>SSH brute-force detection from auth.log</div></li>\n        <li><span class=\"fi\">📁</span><div>File integrity baseline and diff</div></li>\n        <li><span class=\"fi\">🌐</span><div>Network sweep and port enumeration</div></li>\n        <li><span class=\"fi\">⏱️</span><div>Cron-scheduled security checks</div></li>\n      </ul>\n    </div>\n  </div>\n\n  <!-- Script 1: SSH Brute Force Detector -->\n  <div class=\"card ca-g\" style=\"margin-bottom:16px\">\n    <div class=\"card-label\">Script 01 — Log Analysis</div>\n    <div class=\"card-title\" style=\"color:var(--green)\">SSH Brute-Force Detector with Auto-Block</div>\n    <div class=\"card-body\">Parses <code>/var/log/auth.log</code>, counts failed attempts per source IP, sends alerts above threshold, and optionally blocks with <code>iptables</code>. Production-ready with logging and dry-run mode.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">ssh_guard.sh</span>\n        <span class=\"code-pane-lang lang-bash\">BASH</span>\n      </div>\n      <pre><span class=\"t-cmt\">#!/usr/bin/env bash\n# ssh_guard.sh — SSH brute-force detection & response\n# Usage: ./ssh_guard.sh [--dry-run] [--threshold N] [--log FILE]</span>\n\n<span class=\"t-kw\">set</span> -euo pipefail   <span class=\"t-cmt\"># strict mode: exit on error, unset var, pipe fail</span>\n<span class=\"t-kw\">IFS</span>=$'\\n\\t'         <span class=\"t-cmt\"># safer word splitting</span>\n\n<span class=\"t-cmt\"># ── CONFIG (overridable via args) ─────────────────</span>\n<span class=\"t-var\">AUTH_LOG</span>=<span class=\"t-str\">\"/var/log/auth.log\"</span>\n<span class=\"t-var\">THRESHOLD</span>=<span class=\"t-num\">10</span>\n<span class=\"t-var\">DRY_RUN</span>=<span class=\"t-num\">false</span>\n<span class=\"t-var\">LOG_FILE</span>=<span class=\"t-str\">\"/var/log/ssh_guard.log\"</span>\n<span class=\"t-var\">WHITELIST</span>=(<span class=\"t-str\">\"127.0.0.1\"</span> <span class=\"t-str\">\"10.0.0.1\"</span>)  <span class=\"t-cmt\"># never block these</span>\n\n<span class=\"t-cmt\"># ── ARG PARSING ───────────────────────────────────</span>\n<span class=\"t-kw\">while</span> [[ $# -gt <span class=\"t-num\">0</span> ]]; <span class=\"t-kw\">do</span>\n  <span class=\"t-kw\">case</span> <span class=\"t-var\">$1</span> <span class=\"t-kw\">in</span>\n    --dry-run)   DRY_RUN=<span class=\"t-num\">true</span> ;;\n    --threshold) THRESHOLD=<span class=\"t-str\">\"$2\"</span>; shift ;;\n    --log)       AUTH_LOG=<span class=\"t-str\">\"$2\"</span>; shift ;;\n    *) <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"Unknown arg: $1\"</span> &gt;&amp;2; exit <span class=\"t-num\">1</span> ;;\n  <span class=\"t-kw\">esac</span>\n  shift\n<span class=\"t-kw\">done</span>\n\n<span class=\"t-cmt\"># ── HELPERS ───────────────────────────────────────</span>\n<span class=\"t-fn\">log</span>() {\n  <span class=\"t-kw\">local</span> level=<span class=\"t-str\">\"$1\"</span>; shift\n  <span class=\"t-fn\">printf</span> <span class=\"t-str\">'[%s] [%s] %s\\n'</span> <span class=\"t-str\">\"$(date -u +%FT%TZ)\"</span> <span class=\"t-str\">\"$level\"</span> <span class=\"t-str\">\"$*\"</span> <span class=\"t-op\">|</span> \\\n    <span class=\"t-fn\">tee</span> -a <span class=\"t-str\">\"$LOG_FILE\"</span>\n}\n\n<span class=\"t-fn\">is_whitelisted</span>() {\n  <span class=\"t-kw\">local</span> ip=<span class=\"t-str\">\"$1\"</span>\n  <span class=\"t-kw\">for</span> w <span class=\"t-kw\">in</span> <span class=\"t-str\">\"${WHITELIST[@]}\"</span>; <span class=\"t-kw\">do</span>\n    [[ <span class=\"t-str\">\"$ip\"</span> == <span class=\"t-str\">\"$w\"</span> ]] &amp;&amp; <span class=\"t-kw\">return</span> <span class=\"t-num\">0</span>\n  <span class=\"t-kw\">done</span>\n  <span class=\"t-kw\">return</span> <span class=\"t-num\">1</span>\n}\n\n<span class=\"t-fn\">block_ip</span>() {\n  <span class=\"t-kw\">local</span> ip=<span class=\"t-str\">\"$1\"</span>\n  <span class=\"t-kw\">if</span> <span class=\"t-fn\">is_whitelisted</span> <span class=\"t-str\">\"$ip\"</span>; <span class=\"t-kw\">then</span>\n    log WARN <span class=\"t-str\">\"$ip is whitelisted — skipping block\"</span>\n    <span class=\"t-kw\">return</span>\n  <span class=\"t-kw\">fi</span>\n  <span class=\"t-kw\">if</span> [[ <span class=\"t-var\">$DRY_RUN</span> == <span class=\"t-str\">\"true\"</span> ]]; <span class=\"t-kw\">then</span>\n    log DRY  <span class=\"t-str\">\"WOULD block: $ip\"</span>\n  <span class=\"t-kw\">else</span>\n    <span class=\"t-fn\">iptables</span> -A INPUT -s <span class=\"t-str\">\"$ip\"</span> -j DROP\n    log BLOCK <span class=\"t-str\">\"Blocked: $ip\"</span>\n  <span class=\"t-kw\">fi</span>\n}\n\n<span class=\"t-cmt\"># ── MAIN ──────────────────────────────────────────</span>\nlog INFO <span class=\"t-str\">\"Starting scan — threshold=$THRESHOLD, log=$AUTH_LOG\"</span>\n\n<span class=\"t-fn\">grep</span> <span class=\"t-str\">\"Failed password\"</span> <span class=\"t-str\">\"$AUTH_LOG\"</span> \\\n  <span class=\"t-op\">|</span> <span class=\"t-fn\">awk</span> <span class=\"t-str\">'{print $(NF-3)}'</span>           \\\n  <span class=\"t-op\">|</span> <span class=\"t-fn\">grep</span> -Eo <span class=\"t-str\">'[0-9]{1,3}(\\.[0-9]{1,3}){3}'</span> \\\n  <span class=\"t-op\">|</span> <span class=\"t-fn\">sort</span> <span class=\"t-op\">|</span> <span class=\"t-fn\">uniq</span> -c <span class=\"t-op\">|</span> <span class=\"t-fn\">sort</span> -rn \\\n  <span class=\"t-op\">|</span> <span class=\"t-kw\">while</span> <span class=\"t-fn\">read</span> -r count ip; <span class=\"t-kw\">do</span>\n      <span class=\"t-kw\">if</span> [[ <span class=\"t-var\">$count</span> -ge <span class=\"t-var\">$THRESHOLD</span> ]]; <span class=\"t-kw\">then</span>\n        log ALERT <span class=\"t-str\">\"$ip → $count failed attempts\"</span>\n        block_ip <span class=\"t-str\">\"$ip\"</span>\n      <span class=\"t-kw\">fi</span>\n    <span class=\"t-kw\">done</span>\n\nlog INFO <span class=\"t-str\">\"Scan complete\"</span></pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bg\">Strict Mode</span><span class=\"badge bg\">Whitelist</span>\n      <span class=\"badge bg\">Dry-Run</span><span class=\"badge bg\">Timestamped Log</span>\n      <span class=\"badge bg\">Arg Parsing</span>\n    </div>\n  </div>\n\n  <!-- Script 2: File Integrity Monitor -->\n  <div class=\"card ca-g\" style=\"margin-bottom:16px\">\n    <div class=\"card-label\">Script 02 — System Monitoring</div>\n    <div class=\"card-title\" style=\"color:var(--green)\">File Integrity Monitor (Lightweight HIDS)</div>\n    <div class=\"card-body\">Baseline critical system files with SHA-256, then continuously verify them. Alerts on any unauthorized modification — a minimal HIDS.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">fim.sh</span>\n        <span class=\"code-pane-lang lang-bash\">BASH</span>\n      </div>\n      <pre><span class=\"t-cmt\">#!/usr/bin/env bash\n# fim.sh — File Integrity Monitor\n# Usage: ./fim.sh baseline | ./fim.sh check | ./fim.sh watch [interval_secs]</span>\n\n<span class=\"t-kw\">set</span> -euo pipefail\n\n<span class=\"t-var\">WATCH_FILES</span>=(\n  <span class=\"t-str\">\"/etc/passwd\"</span> <span class=\"t-str\">\"/etc/shadow\"</span> <span class=\"t-str\">\"/etc/sudoers\"</span>\n  <span class=\"t-str\">\"/etc/ssh/sshd_config\"</span> <span class=\"t-str\">\"/etc/crontab\"</span>\n  <span class=\"t-str\">\"/etc/hosts\"</span> <span class=\"t-str\">\"/etc/ld.so.preload\"</span>\n)\n<span class=\"t-var\">BASELINE_DB</span>=<span class=\"t-str\">\"/var/lib/fim/baseline.db\"</span>\n<span class=\"t-var\">ALERT_LOG</span>=<span class=\"t-str\">\"/var/log/fim_alerts.log\"</span>\n\n<span class=\"t-fn\">mkdir</span> -p <span class=\"t-str\">\"$(dirname \"$BASELINE_DB\")\"</span>\n\n<span class=\"t-fn\">hash_file</span>() {\n  <span class=\"t-fn\">sha256sum</span> <span class=\"t-str\">\"$1\"</span> <span class=\"t-num\">2</span>&gt;/dev/null <span class=\"t-op\">|</span> <span class=\"t-fn\">cut</span> -d' ' -f1\n}\n\n<span class=\"t-fn\">do_baseline</span>() {\n  <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"[$(date -u +%FT%TZ)] Generating baseline...\"</span>\n  <span class=\"t-kw\">true</span> &gt; <span class=\"t-str\">\"$BASELINE_DB\"</span>\n  <span class=\"t-kw\">for</span> f <span class=\"t-kw\">in</span> <span class=\"t-str\">\"${WATCH_FILES[@]}\"</span>; <span class=\"t-kw\">do</span>\n    <span class=\"t-kw\">if</span> [[ -f <span class=\"t-str\">\"$f\"</span> ]]; <span class=\"t-kw\">then</span>\n      <span class=\"t-fn\">printf</span> <span class=\"t-str\">'%s  %s\\n'</span> <span class=\"t-str\">\"$(hash_file \"$f\")\"</span> <span class=\"t-str\">\"$f\"</span> &gt;&gt; <span class=\"t-str\">\"$BASELINE_DB\"</span>\n      <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"  ✓ $f\"</span>\n    <span class=\"t-kw\">else</span>\n      <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"  ✗ NOT FOUND: $f\"</span>\n    <span class=\"t-kw\">fi</span>\n  <span class=\"t-kw\">done</span>\n  <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"Baseline saved → $BASELINE_DB\"</span>\n}\n\n<span class=\"t-fn\">do_check</span>() {\n  <span class=\"t-kw\">local</span> violations=<span class=\"t-num\">0</span>\n  <span class=\"t-kw\">while</span> <span class=\"t-fn\">read</span> -r expected_hash filepath; <span class=\"t-kw\">do</span>\n    <span class=\"t-kw\">if</span> [[ ! -f <span class=\"t-str\">\"$filepath\"</span> ]]; <span class=\"t-kw\">then</span>\n      <span class=\"t-fn\">alert</span> <span class=\"t-str\">\"DELETED\"</span> <span class=\"t-str\">\"$filepath\"</span>; (( violations++ ))\n      <span class=\"t-kw\">continue</span>\n    <span class=\"t-kw\">fi</span>\n    <span class=\"t-kw\">local</span> current_hash; current_hash=<span class=\"t-str\">\"$(hash_file \"$filepath\")\"</span>\n    <span class=\"t-kw\">if</span> [[ <span class=\"t-str\">\"$current_hash\"</span> != <span class=\"t-str\">\"$expected_hash\"</span> ]]; <span class=\"t-kw\">then</span>\n      <span class=\"t-fn\">alert</span> <span class=\"t-str\">\"MODIFIED\"</span> <span class=\"t-str\">\"$filepath\"</span>\n      <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"    was: $expected_hash\"</span>\n      <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"    now: $current_hash\"</span>\n      (( violations++ ))\n    <span class=\"t-kw\">fi</span>\n  <span class=\"t-kw\">done</span> &lt; <span class=\"t-str\">\"$BASELINE_DB\"</span>\n  [[ <span class=\"t-var\">$violations</span> -eq <span class=\"t-num\">0</span> ]] &amp;&amp; <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"[OK] All files intact\"</span>\n  <span class=\"t-kw\">return</span> <span class=\"t-var\">$violations</span>\n}\n\n<span class=\"t-fn\">alert</span>() {\n  <span class=\"t-kw\">local</span> msg; msg=<span class=\"t-str\">\"[$(date -u +%FT%TZ)] [ALERT] $1: $2\"</span>\n  <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"$msg\"</span> <span class=\"t-op\">|</span> <span class=\"t-fn\">tee</span> -a <span class=\"t-str\">\"$ALERT_LOG\"</span>\n  <span class=\"t-cmt\"># Hook: send to SIEM, Slack webhook, email, etc.</span>\n}\n\n<span class=\"t-kw\">case</span> <span class=\"t-str\">\"${1:-check}\"</span> <span class=\"t-kw\">in</span>\n  baseline) do_baseline ;;\n  check)    do_check ;;\n  watch)\n    interval=<span class=\"t-str\">\"${2:-300}\"</span>\n    <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"Watching every ${interval}s — Ctrl+C to stop\"</span>\n    <span class=\"t-kw\">while true</span>; <span class=\"t-kw\">do</span> do_check; sleep <span class=\"t-str\">\"$interval\"</span>; <span class=\"t-kw\">done</span> ;;\n  *) <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"Usage: $0 baseline|check|watch [interval]\"</span>; exit <span class=\"t-num\">1</span> ;;\n<span class=\"t-kw\">esac</span></pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bg\">SHA-256</span><span class=\"badge bg\">Baseline Mode</span>\n      <span class=\"badge bg\">Watch Loop</span><span class=\"badge bg\">Alert Hook</span>\n    </div>\n  </div>\n\n  <!-- Script 3: Network Sweep -->\n  <div class=\"card ca-g\">\n    <div class=\"card-label\">Script 03 — Network Monitoring</div>\n    <div class=\"card-title\" style=\"color:var(--green)\">Network Asset Discovery & Change Detector</div>\n    <div class=\"card-body\">Pings a subnet, grabs hostnames, baselines the inventory, and alerts when new or missing hosts appear — lightweight asset tracking without nmap.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">net_sweep.sh</span>\n        <span class=\"code-pane-lang lang-bash\">BASH</span>\n      </div>\n      <pre><span class=\"t-cmt\">#!/usr/bin/env bash\n# net_sweep.sh — Subnet sweep & change detection\n# Usage: ./net_sweep.sh 192.168.1 [--baseline]</span>\n\n<span class=\"t-kw\">set</span> -euo pipefail\n<span class=\"t-var\">SUBNET</span>=<span class=\"t-str\">\"${1:-192.168.1}\"</span>\n<span class=\"t-var\">BASELINE</span>=<span class=\"t-str\">\"/tmp/net_baseline_${SUBNET//./_}.txt\"</span>\n<span class=\"t-var\">CURRENT</span>=$(mktemp)\n<span class=\"t-kw\">trap</span> <span class=\"t-str\">'rm -f \"$CURRENT\"'</span> EXIT\n\n<span class=\"t-fn\">sweep</span>() {\n  <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"[*] Sweeping $SUBNET.0/24...\"</span>\n  <span class=\"t-kw\">for</span> i <span class=\"t-kw\">in</span> $(<span class=\"t-fn\">seq</span> <span class=\"t-num\">1</span> <span class=\"t-num\">254</span>); <span class=\"t-kw\">do</span>\n    {\n      ip=<span class=\"t-str\">\"$SUBNET.$i\"</span>\n      <span class=\"t-kw\">if</span> <span class=\"t-fn\">ping</span> -c1 -W1 <span class=\"t-str\">\"$ip\"</span> &gt;/dev/null <span class=\"t-num\">2</span>&gt;&amp;<span class=\"t-num\">1</span>; <span class=\"t-kw\">then</span>\n        host_name=$(<span class=\"t-fn\">dig</span> +short -x <span class=\"t-str\">\"$ip\"</span> <span class=\"t-num\">2</span>&gt;/dev/null <span class=\"t-op\">||</span> <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"unknown\"</span>)\n        <span class=\"t-fn\">printf</span> <span class=\"t-str\">'%s %s\\n'</span> <span class=\"t-str\">\"$ip\"</span> <span class=\"t-str\">\"${host_name%.}\"</span> &gt;&gt; <span class=\"t-str\">\"$CURRENT\"</span>\n      <span class=\"t-kw\">fi</span>\n    } &amp;  <span class=\"t-cmt\"># parallel pings</span>\n  <span class=\"t-kw\">done</span>\n  wait  <span class=\"t-cmt\"># wait for all background jobs</span>\n  <span class=\"t-fn\">sort</span> -t. -k4 -n <span class=\"t-str\">\"$CURRENT\"</span>\n}\n\n<span class=\"t-kw\">if</span> [[ <span class=\"t-str\">\"${2:-}\"</span> == <span class=\"t-str\">\"--baseline\"</span> ]]; <span class=\"t-kw\">then</span>\n  sweep &gt; <span class=\"t-str\">\"$BASELINE\"</span>\n  <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"[✓] Baseline saved: $BASELINE ($(wc -l &lt;\"$BASELINE\") hosts)\"</span>\n<span class=\"t-kw\">elif</span> [[ -f <span class=\"t-str\">\"$BASELINE\"</span> ]]; <span class=\"t-kw\">then</span>\n  sweep &gt; <span class=\"t-str\">\"$CURRENT\"</span>\n  <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"=== NEW HOSTS ===\"</span>\n  <span class=\"t-fn\">comm</span> -13 &lt;(<span class=\"t-fn\">sort</span> <span class=\"t-str\">\"$BASELINE\"</span>) &lt;(<span class=\"t-fn\">sort</span> <span class=\"t-str\">\"$CURRENT\"</span>) <span class=\"t-op\">|</span> <span class=\"t-fn\">grep</span> . <span class=\"t-op\">||</span> <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"None\"</span>\n  <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"=== MISSING HOSTS ===\"</span>\n  <span class=\"t-fn\">comm</span> -23 &lt;(<span class=\"t-fn\">sort</span> <span class=\"t-str\">\"$BASELINE\"</span>) &lt;(<span class=\"t-fn\">sort</span> <span class=\"t-str\">\"$CURRENT\"</span>) <span class=\"t-op\">|</span> <span class=\"t-fn\">grep</span> . <span class=\"t-op\">||</span> <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"None\"</span>\n<span class=\"t-kw\">else</span>\n  <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"No baseline — run with --baseline first\"</span>\n<span class=\"t-kw\">fi</span></pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bg\">Parallel</span><span class=\"badge bg\">Trap Cleanup</span><span class=\"badge bg\">Change Detection</span>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     MODULE: PYTHON\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-python\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">02</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-tag\">// Python Security Scripting //</div>\n      <div class=\"sh-title\" style=\"color:var(--cyan)\">Python for Security</div>\n      <div class=\"sh-desc\">The analyst's powerhouse. Rich stdlib, battle-tested libraries — scapy, requests, cryptography — and readable code that scales from 20-line scripts to full frameworks.</div>\n    </div>\n  </div>\n\n  <div class=\"g3\" style=\"margin-bottom:20px\">\n    <div class=\"card ca-c\">\n      <div class=\"card-label\">Key Libraries</div>\n      <div class=\"card-title\" style=\"color:var(--cyan)\">Security Toolkit</div>\n      <ul class=\"feature-list\">\n        <li><span class=\"fi\">▸</span><div><code>scapy</code> — packet crafting & sniffing</div></li>\n        <li><span class=\"fi\">▸</span><div><code>requests</code> — HTTP client for API interactions</div></li>\n        <li><span class=\"fi\">▸</span><div><code>cryptography</code> — encryption & hashing primitives</div></li>\n        <li><span class=\"fi\">▸</span><div><code>paramiko</code> — SSH automation</div></li>\n        <li><span class=\"fi\">▸</span><div><code>yara-python</code> — malware classification</div></li>\n        <li><span class=\"fi\">▸</span><div><code>volatility3</code> — memory forensics API</div></li>\n      </ul>\n    </div>\n    <div class=\"card ca-c\">\n      <div class=\"card-label\">Architecture Pattern</div>\n      <div class=\"card-title\" style=\"color:var(--cyan)\">Security Script Structure</div>\n      <div class=\"code-pane\">\n        <div class=\"code-pane-bar\">\n          <span class=\"code-pane-name\">template.py</span>\n          <span class=\"code-pane-lang lang-python\">PYTHON</span>\n        </div>\n        <pre><span class=\"t-cmt\">#!/usr/bin/env python3</span>\n<span class=\"t-kw\">import</span> argparse, logging, sys\n<span class=\"t-kw\">from</span> pathlib <span class=\"t-kw\">import</span> Path\n\n<span class=\"t-fn\">logging</span>.basicConfig(\n  level=logging.INFO,\n  format=<span class=\"t-str\">'%(asctime)s [%(levelname)s] %(message)s'</span>,\n  datefmt=<span class=\"t-str\">'%Y-%m-%dT%H:%M:%SZ'</span>\n)\nlog = logging.getLogger(__name__)\n\n<span class=\"t-kw\">def</span> <span class=\"t-fn\">parse_args</span>():\n  p = argparse.ArgumentParser()\n  p.add_argument(<span class=\"t-str\">'--target'</span>, required=<span class=\"t-num\">True</span>)\n  p.add_argument(<span class=\"t-str\">'--dry-run'</span>, action=<span class=\"t-str\">'store_true'</span>)\n  <span class=\"t-kw\">return</span> p.parse_args()\n\n<span class=\"t-kw\">def</span> <span class=\"t-fn\">main</span>():\n  args = parse_args()\n  <span class=\"t-cmt\"># your logic here</span>\n\n<span class=\"t-kw\">if</span> __name__ == <span class=\"t-str\">'__main__'</span>:\n  sys.exit(main())</pre>\n      </div>\n    </div>\n    <div class=\"card ca-c\">\n      <div class=\"card-label\">When Python Wins</div>\n      <div class=\"card-title\" style=\"color:var(--cyan)\">Choose Python For</div>\n      <ul class=\"feature-list\">\n        <li><span class=\"fi\">🔬</span><div>Complex log parsing with regex/parsing libs</div></li>\n        <li><span class=\"fi\">🌐</span><div>API calls to SIEM, VirusTotal, Shodan</div></li>\n        <li><span class=\"fi\">🔐</span><div>Cryptographic operations (never roll your own)</div></li>\n        <li><span class=\"fi\">📦</span><div>Building reusable security tool frameworks</div></li>\n        <li><span class=\"fi\">🧪</span><div>Malware analysis automation pipelines</div></li>\n      </ul>\n    </div>\n  </div>\n\n  <!-- Python Script 1: Log Analyzer -->\n  <div class=\"card ca-c\" style=\"margin-bottom:16px\">\n    <div class=\"card-label\">Script 04 — SIEM-style Log Analyzer</div>\n    <div class=\"card-title\" style=\"color:var(--cyan)\">Multi-Source Log Parser with IOC Detection</div>\n    <div class=\"card-body\">Parses multiple log formats, extracts IOCs (IPs, domains, hashes), correlates against a threat intel feed, and produces a structured JSON report.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">log_analyzer.py</span>\n        <span class=\"code-pane-lang lang-python\">PYTHON</span>\n      </div>\n      <pre><span class=\"t-cmt\">#!/usr/bin/env python3\n\"\"\"\nlog_analyzer.py — Multi-format log parser with IOC detection\nSupports: auth.log, nginx access.log, syslog, JSON logs\n\"\"\"</span>\n\n<span class=\"t-kw\">import</span> re, json, sys, argparse, logging\n<span class=\"t-kw\">from</span> pathlib    <span class=\"t-kw\">import</span> Path\n<span class=\"t-kw\">from</span> datetime   <span class=\"t-kw\">import</span> datetime, timezone\n<span class=\"t-kw\">from</span> collections <span class=\"t-kw\">import</span> defaultdict, Counter\n<span class=\"t-kw\">from</span> ipaddress  <span class=\"t-kw\">import</span> ip_address, ip_network, AddressValueError\n\nlog = logging.getLogger(__name__)\n\n<span class=\"t-cmt\"># ── PATTERNS ──────────────────────────────────────────</span>\nPATTERNS = {\n  <span class=\"t-str\">'ipv4'</span>:   <span class=\"t-fn\">re</span>.compile(\n    <span class=\"t-str\">r'\\b(?:(?:25[0-5]|2[0-4]\\d|[01]?\\d\\d?)\\.){3}(?:25[0-5]|2[0-4]\\d|[01]?\\d\\d?)\\b'</span>\n  ),\n  <span class=\"t-str\">'domain'</span>: <span class=\"t-fn\">re</span>.compile(\n    <span class=\"t-str\">r'\\b(?:[a-zA-Z0-9](?:[a-zA-Z0-9\\-]{0,61}[a-zA-Z0-9])?\\.)+[a-zA-Z]{2,}\\b'</span>\n  ),\n  <span class=\"t-str\">'hash_sha256'</span>: <span class=\"t-fn\">re</span>.compile(<span class=\"t-str\">r'\\b[0-9a-fA-F]{64}\\b'</span>),\n  <span class=\"t-str\">'hash_md5'</span>:    <span class=\"t-fn\">re</span>.compile(<span class=\"t-str\">r'\\b[0-9a-fA-F]{32}\\b'</span>),\n}\n\n<span class=\"t-cmt\"># Private ranges — skip these from IOC reports</span>\nPRIVATE_RANGES = [\n  ip_network(<span class=\"t-str\">'10.0.0.0/8'</span>), ip_network(<span class=\"t-str\">'172.16.0.0/12'</span>),\n  ip_network(<span class=\"t-str\">'192.168.0.0/16'</span>), ip_network(<span class=\"t-str\">'127.0.0.0/8'</span>),\n]\n\n<span class=\"t-kw\">class</span> <span class=\"t-fn\">LogAnalyzer</span>:\n  <span class=\"t-kw\">def</span> <span class=\"t-fn\">__init__</span>(self, threat_feed: <span class=\"t-fn\">set</span> = None):\n    self.events      = []\n    self.iocs        = defaultdict(<span class=\"t-fn\">set</span>)\n    self.ip_counts   = Counter()\n    self.threat_hits = []\n    self.threat_feed = threat_feed <span class=\"t-kw\">or</span> <span class=\"t-fn\">set</span>()\n\n  <span class=\"t-kw\">def</span> <span class=\"t-fn\">is_private</span>(self, ip_str: str) -> bool:\n    <span class=\"t-kw\">try</span>:\n      addr = ip_address(ip_str)\n      <span class=\"t-kw\">return</span> <span class=\"t-fn\">any</span>(addr <span class=\"t-kw\">in</span> net <span class=\"t-kw\">for</span> net <span class=\"t-kw\">in</span> PRIVATE_RANGES)\n    <span class=\"t-kw\">except</span> AddressValueError:\n      <span class=\"t-kw\">return</span> False\n\n  <span class=\"t-kw\">def</span> <span class=\"t-fn\">extract_iocs</span>(self, line: str) -> <span class=\"t-fn\">dict</span>:\n    found = {}\n    <span class=\"t-kw\">for</span> ioc_type, pattern <span class=\"t-kw\">in</span> PATTERNS.items():\n      matches = pattern.findall(line)\n      <span class=\"t-kw\">if</span> ioc_type == <span class=\"t-str\">'ipv4'</span>:\n        matches = [m <span class=\"t-kw\">for</span> m <span class=\"t-kw\">in</span> matches <span class=\"t-kw\">if not</span> self.is_private(m)]\n      <span class=\"t-kw\">if</span> matches:\n        found[ioc_type] = <span class=\"t-fn\">list</span>(<span class=\"t-fn\">set</span>(matches))\n        self.iocs[ioc_type].update(matches)\n    <span class=\"t-kw\">return</span> found\n\n  <span class=\"t-kw\">def</span> <span class=\"t-fn\">analyze_line</span>(self, line: str, source: str) -> None:\n    iocs = self.extract_iocs(line)\n    <span class=\"t-kw\">if not</span> iocs:\n      <span class=\"t-kw\">return</span>\n    event = {<span class=\"t-str\">'source'</span>: source, <span class=\"t-str\">'raw'</span>: line.strip()[:300], <span class=\"t-str\">'iocs'</span>: iocs}\n\n    <span class=\"t-cmt\"># Threat intel correlation</span>\n    <span class=\"t-kw\">for</span> ip <span class=\"t-kw\">in</span> iocs.get(<span class=\"t-str\">'ipv4'</span>, []):\n      self.ip_counts[ip] += <span class=\"t-num\">1</span>\n      <span class=\"t-kw\">if</span> ip <span class=\"t-kw\">in</span> self.threat_feed:\n        event[<span class=\"t-str\">'threat_match'</span>] = ip\n        self.threat_hits.append(event)\n        log.warning(<span class=\"t-str\">f\"[THREAT MATCH] {ip} in threat feed — line: {line[:80]}\"</span>)\n    self.events.append(event)\n\n  <span class=\"t-kw\">def</span> <span class=\"t-fn\">process_file</span>(self, path: Path) -> None:\n    log.info(<span class=\"t-str\">f\"Processing: {path}\"</span>)\n    <span class=\"t-kw\">with</span> <span class=\"t-fn\">open</span>(path, <span class=\"t-str\">'r'</span>, errors=<span class=\"t-str\">'replace'</span>) <span class=\"t-kw\">as</span> fh:\n      <span class=\"t-kw\">for</span> line <span class=\"t-kw\">in</span> fh:\n        self.analyze_line(line, str(path))\n\n  <span class=\"t-kw\">def</span> <span class=\"t-fn\">report</span>(self) -> <span class=\"t-fn\">dict</span>:\n    <span class=\"t-kw\">return</span> {\n      <span class=\"t-str\">'generated_at'</span>: datetime.now(timezone.utc).isoformat(),\n      <span class=\"t-str\">'summary'</span>: {\n        <span class=\"t-str\">'total_events'</span>:   <span class=\"t-fn\">len</span>(self.events),\n        <span class=\"t-str\">'unique_ips'</span>:      <span class=\"t-fn\">len</span>(self.iocs.get(<span class=\"t-str\">'ipv4'</span>, [])),\n        <span class=\"t-str\">'threat_hits'</span>:    <span class=\"t-fn\">len</span>(self.threat_hits),\n      },\n      <span class=\"t-str\">'top_ips'</span>:      self.ip_counts.most_common(<span class=\"t-num\">20</span>),\n      <span class=\"t-str\">'threat_events'</span>: self.threat_hits,\n      <span class=\"t-str\">'all_iocs'</span>:      {k: <span class=\"t-fn\">list</span>(v) <span class=\"t-kw\">for</span> k, v <span class=\"t-kw\">in</span> self.iocs.items()},\n    }\n\n<span class=\"t-kw\">def</span> <span class=\"t-fn\">main</span>():\n  p = argparse.ArgumentParser(description=<span class=\"t-str\">'Log analyzer with IOC detection'</span>)\n  p.add_argument(<span class=\"t-str\">'logs'</span>, nargs=<span class=\"t-str\">'+'</span>, help=<span class=\"t-str\">'Log files to analyze'</span>)\n  p.add_argument(<span class=\"t-str\">'--feed'</span>, help=<span class=\"t-str\">'Threat feed file (one IP per line)'</span>)\n  p.add_argument(<span class=\"t-str\">'--out'</span>, default=<span class=\"t-str\">'report.json'</span>)\n  args = p.parse_args()\n\n  feed = <span class=\"t-fn\">set</span>()\n  <span class=\"t-kw\">if</span> args.feed:\n    feed = {ln.strip() <span class=\"t-kw\">for</span> ln <span class=\"t-kw\">in</span> Path(args.feed).read_text().splitlines() <span class=\"t-kw\">if</span> ln.strip()}\n\n  analyzer = LogAnalyzer(threat_feed=feed)\n  <span class=\"t-kw\">for</span> log_path <span class=\"t-kw\">in</span> args.logs:\n    analyzer.process_file(Path(log_path))\n\n  report = analyzer.report()\n  Path(args.out).write_text(json.dumps(report, indent=<span class=\"t-num\">2</span>))\n  log.info(<span class=\"t-str\">f\"Report → {args.out} | Threats: {report['summary']['threat_hits']}\"</span>)\n\n<span class=\"t-kw\">if</span> __name__ == <span class=\"t-str\">'__main__'</span>:\n  logging.basicConfig(level=logging.INFO)\n  main()</pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bc\">IOC Extraction</span><span class=\"badge bc\">Threat Intel</span>\n      <span class=\"badge bc\">Private IP Filter</span><span class=\"badge bc\">JSON Report</span><span class=\"badge bc\">Multi-Source</span>\n    </div>\n  </div>\n\n  <!-- Python Script 2: VirusTotal Enrichment -->\n  <div class=\"card ca-c\">\n    <div class=\"card-label\">Script 05 — Threat Intel Enrichment</div>\n    <div class=\"card-title\" style=\"color:var(--cyan)\">VirusTotal API — Bulk IOC Enrichment</div>\n    <div class=\"card-body\">Takes a list of file hashes, IPs, or domains, queries the VirusTotal API with rate limiting, and enriches each with verdicts, detection ratios, and tags.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">vt_enrich.py</span>\n        <span class=\"code-pane-lang lang-python\">PYTHON</span>\n      </div>\n      <pre><span class=\"t-cmt\">#!/usr/bin/env python3\n\"\"\"\nvt_enrich.py — VirusTotal bulk IOC enrichment\nRate-limited, retry-safe, outputs enriched JSON\n\"\"\"</span>\n<span class=\"t-kw\">import</span> time, json, sys, os\n<span class=\"t-kw\">import</span> requests\n<span class=\"t-kw\">from</span> pathlib <span class=\"t-kw\">import</span> Path\n\n<span class=\"t-var\">VT_BASE</span>    = <span class=\"t-str\">\"https://www.virustotal.com/api/v3\"</span>\n<span class=\"t-var\">API_KEY</span>    = os.environ.get(<span class=\"t-str\">\"VT_API_KEY\"</span>, <span class=\"t-str\">\"\"</span>)  <span class=\"t-cmt\"># NEVER hardcode keys</span>\n<span class=\"t-var\">RATE_LIMIT</span> = <span class=\"t-num\">4</span>   <span class=\"t-cmt\"># free tier: 4 req/min</span>\n<span class=\"t-var\">DELAY</span>      = <span class=\"t-num\">60</span> / RATE_LIMIT\n\n<span class=\"t-kw\">def</span> <span class=\"t-fn\">vt_lookup</span>(ioc: str, ioc_type: str) -> <span class=\"t-fn\">dict</span>:\n  <span class=\"t-cmt\">\"\"\"Query VT for hash|ip|domain with retry on 429.\"\"\"</span>\n  endpoints = {\n    <span class=\"t-str\">'hash'</span>:   <span class=\"t-str\">f\"/files/{ioc}\"</span>,\n    <span class=\"t-str\">'ip'</span>:     <span class=\"t-str\">f\"/ip_addresses/{ioc}\"</span>,\n    <span class=\"t-str\">'domain'</span>: <span class=\"t-str\">f\"/domains/{ioc}\"</span>,\n  }\n  url = VT_BASE + endpoints[ioc_type]\n  headers = {<span class=\"t-str\">\"x-apikey\"</span>: API_KEY}\n\n  <span class=\"t-kw\">for</span> attempt <span class=\"t-kw\">in</span> <span class=\"t-fn\">range</span>(<span class=\"t-num\">3</span>):\n    resp = requests.get(url, headers=headers, timeout=<span class=\"t-num\">15</span>)\n    <span class=\"t-kw\">if</span> resp.status_code == <span class=\"t-num\">200</span>:\n      data = resp.json().get(<span class=\"t-str\">\"data\"</span>, {}).get(<span class=\"t-str\">\"attributes\"</span>, {})\n      stats = data.get(<span class=\"t-str\">\"last_analysis_stats\"</span>, {})\n      <span class=\"t-kw\">return</span> {\n        <span class=\"t-str\">\"ioc\"</span>:      ioc,\n        <span class=\"t-str\">\"type\"</span>:     ioc_type,\n        <span class=\"t-str\">\"malicious\"</span>:  stats.get(<span class=\"t-str\">\"malicious\"</span>, <span class=\"t-num\">0</span>),\n        <span class=\"t-str\">\"suspicious\"</span>: stats.get(<span class=\"t-str\">\"suspicious\"</span>, <span class=\"t-num\">0</span>),\n        <span class=\"t-str\">\"undetected\"</span>: stats.get(<span class=\"t-str\">\"undetected\"</span>, <span class=\"t-num\">0</span>),\n        <span class=\"t-str\">\"tags\"</span>:     data.get(<span class=\"t-str\">\"tags\"</span>, []),\n        <span class=\"t-str\">\"verdict\"</span>:  <span class=\"t-str\">\"MALICIOUS\"</span> <span class=\"t-kw\">if</span> stats.get(<span class=\"t-str\">\"malicious\"</span>, <span class=\"t-num\">0</span>) &gt; <span class=\"t-num\">2</span> <span class=\"t-kw\">else</span> <span class=\"t-str\">\"CLEAN\"</span>,\n      }\n    <span class=\"t-kw\">elif</span> resp.status_code == <span class=\"t-num\">429</span>:\n      wait = <span class=\"t-num\">60</span> * (attempt + <span class=\"t-num\">1</span>)\n      <span class=\"t-fn\">print</span>(<span class=\"t-str\">f\"Rate limited — waiting {wait}s...\"</span>, file=sys.stderr)\n      time.sleep(wait)\n    <span class=\"t-kw\">elif</span> resp.status_code == <span class=\"t-num\">404</span>:\n      <span class=\"t-kw\">return</span> {<span class=\"t-str\">\"ioc\"</span>: ioc, <span class=\"t-str\">\"verdict\"</span>: <span class=\"t-str\">\"NOT_FOUND\"</span>}\n    <span class=\"t-kw\">else</span>:\n      <span class=\"t-kw\">return</span> {<span class=\"t-str\">\"ioc\"</span>: ioc, <span class=\"t-str\">\"error\"</span>: resp.status_code}\n  <span class=\"t-kw\">return</span> {<span class=\"t-str\">\"ioc\"</span>: ioc, <span class=\"t-str\">\"error\"</span>: <span class=\"t-str\">\"max_retries\"</span>}\n\n<span class=\"t-kw\">def</span> <span class=\"t-fn\">enrich_list</span>(iocs: list, ioc_type: str) -> list:\n  results = []\n  <span class=\"t-kw\">for</span> i, ioc <span class=\"t-kw\">in</span> <span class=\"t-fn\">enumerate</span>(iocs):\n    <span class=\"t-fn\">print</span>(<span class=\"t-str\">f\"[{i+1}/{len(iocs)}] Querying: {ioc}\"</span>)\n    result = vt_lookup(ioc.strip(), ioc_type)\n    results.append(result)\n    <span class=\"t-kw\">if</span> result.get(<span class=\"t-str\">\"verdict\"</span>) == <span class=\"t-str\">\"MALICIOUS\"</span>:\n      <span class=\"t-fn\">print</span>(<span class=\"t-str\">f\"  ⚠ MALICIOUS — {result['malicious']} engines\"</span>)\n    time.sleep(DELAY)  <span class=\"t-cmt\"># respect rate limit</span>\n  <span class=\"t-kw\">return</span> results\n\n<span class=\"t-kw\">if</span> __name__ == <span class=\"t-str\">\"__main__\"</span>:\n  <span class=\"t-kw\">if not</span> API_KEY:\n    sys.exit(<span class=\"t-str\">\"Set VT_API_KEY environment variable\"</span>)\n  <span class=\"t-cmt\"># Example: pipe hashes from file</span>\n  hashes = sys.stdin.read().splitlines()\n  results = enrich_list(hashes, <span class=\"t-str\">\"hash\"</span>)\n  Path(<span class=\"t-str\">\"vt_results.json\"</span>).write_text(json.dumps(results, indent=<span class=\"t-num\">2</span>))</pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bc\">No Hardcoded Keys</span><span class=\"badge bc\">Rate Limiting</span>\n      <span class=\"badge bc\">Retry Logic</span><span class=\"badge bc\">Bulk Processing</span>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     MODULE: POWERSHELL\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-pwsh\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">03</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-tag\">// Windows Security Scripting //</div>\n      <div class=\"sh-title\" style=\"color:var(--purple)\">PowerShell for Security</div>\n      <div class=\"sh-desc\">Deep Windows integration, .NET object pipeline, and native access to WMI, registry, event logs, and Active Directory. The defender's Windows operating language.</div>\n    </div>\n  </div>\n\n  <div class=\"g2\" style=\"margin-bottom:16px\">\n    <div class=\"card ca-p\">\n      <div class=\"card-label\">Why PowerShell</div>\n      <div class=\"card-title\" style=\"color:var(--purple)\">Native Windows Power</div>\n      <ul class=\"feature-list\">\n        <li><span class=\"fi\">▸</span><div><strong>Object pipeline</strong> — pass .NET objects, not text strings</div></li>\n        <li><span class=\"fi\">▸</span><div><strong>WMI/CIM</strong> — query system state deeply</div></li>\n        <li><span class=\"fi\">▸</span><div><strong>Event logs</strong> — native Get-WinEvent access</div></li>\n        <li><span class=\"fi\">▸</span><div><strong>Active Directory</strong> — enumerate users, groups, GPOs</div></li>\n        <li><span class=\"fi\">▸</span><div><strong>Constrained Language Mode</strong> — understand attacker bypasses</div></li>\n      </ul>\n    </div>\n    <div class=\"card ca-p\">\n      <div class=\"card-label\">Security Context</div>\n      <div class=\"card-title\" style=\"color:var(--purple)\">Living-Off-the-Land</div>\n      <div class=\"card-body\">Attackers abuse PowerShell extensively (<strong>LOLBins</strong>). Understanding it as a defender means knowing <em>what normal looks like</em> — so you can detect the abnormal. Enable <strong>Script Block Logging</strong> and <strong>Module Logging</strong> in production environments.</div>\n      <div class=\"code-pane\">\n        <div class=\"code-pane-bar\"><span class=\"code-pane-name\">Enable Logging</span><span class=\"code-pane-lang lang-pwsh\">PWSH</span></div>\n        <pre><span class=\"t-cmt\"># Enable PowerShell Script Block Logging (GPO or registry)</span>\n<span class=\"t-var\">$path</span> = <span class=\"t-str\">'HKLM:\\SOFTWARE\\Policies\\Microsoft\\Windows\\PowerShell\\ScriptBlockLogging'</span>\n<span class=\"t-fn\">New-Item</span> -Path <span class=\"t-var\">$path</span> -Force\n<span class=\"t-fn\">Set-ItemProperty</span> -Path <span class=\"t-var\">$path</span> -Name <span class=\"t-str\">\"EnableScriptBlockLogging\"</span> -Value <span class=\"t-num\">1</span>\n<span class=\"t-cmt\"># Logs to: Event ID 4104 — Microsoft-Windows-PowerShell/Operational</span></pre>\n      </div>\n    </div>\n  </div>\n\n  <!-- PowerShell Script 1 -->\n  <div class=\"card ca-p\" style=\"margin-bottom:16px\">\n    <div class=\"card-label\">Script 06 — Threat Hunting</div>\n    <div class=\"card-title\" style=\"color:var(--purple)\">Windows Threat Hunting Script</div>\n    <div class=\"card-body\">Comprehensive host triage — unsigned processes, suspicious parent-child chains, persistence mechanisms, network connections. Outputs structured report.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">Invoke-ThreatHunt.ps1</span>\n        <span class=\"code-pane-lang lang-pwsh\">PWSH</span>\n      </div>\n      <pre><span class=\"t-cmt\">#Requires -RunAsAdministrator\n<# .SYNOPSIS\n   Invoke-ThreatHunt.ps1 — Host triage & threat hunting\n   Run from an elevated PowerShell session in a sandbox\n#></span>\n\n<span class=\"t-fn\">Set-StrictMode</span> -Version Latest\n<span class=\"t-var\">$ErrorActionPreference</span> = <span class=\"t-str\">'Continue'</span>\n<span class=\"t-var\">$report</span> = [ordered]@{ Timestamp = (Get-Date -Format o); Findings = @() }\n\n<span class=\"t-kw\">function</span> <span class=\"t-fn\">Add-Finding</span>([string]<span class=\"t-var\">$Category</span>, [string]<span class=\"t-var\">$Severity</span>, [string]<span class=\"t-var\">$Detail</span>, <span class=\"t-var\">$Data</span>) {\n  <span class=\"t-var\">$report</span>.Findings += [PSCustomObject]@{\n    Category = <span class=\"t-var\">$Category</span>; Severity = <span class=\"t-var\">$Severity</span>\n    Detail   = <span class=\"t-var\">$Detail</span>;   Data     = <span class=\"t-var\">$Data</span>\n  }\n  <span class=\"t-var\">$color</span> = <span class=\"t-kw\">switch</span> (<span class=\"t-var\">$Severity</span>) { <span class=\"t-str\">'HIGH'</span> {<span class=\"t-str\">'Red'</span>} <span class=\"t-str\">'MED'</span> {<span class=\"t-str\">'Yellow'</span>} <span class=\"t-kw\">default</span> {<span class=\"t-str\">'Cyan'</span>}}\n  <span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[$Severity] $Category → $Detail\"</span> -ForegroundColor <span class=\"t-var\">$color</span>\n}\n\n<span class=\"t-cmt\"># ── 1. UNSIGNED PROCESSES ─────────────────────────</span>\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"`n[*] Checking process signatures...\"</span>\n<span class=\"t-fn\">Get-Process</span> | <span class=\"t-fn\">ForEach-Object</span> {\n  <span class=\"t-kw\">try</span> {\n    <span class=\"t-var\">$path</span> = <span class=\"t-var\">$_</span>.MainModule.FileName\n    <span class=\"t-kw\">if</span> (<span class=\"t-var\">$null</span> -eq <span class=\"t-var\">$path</span>) { <span class=\"t-kw\">return</span> }\n    <span class=\"t-var\">$sig</span> = <span class=\"t-fn\">Get-AuthenticodeSignature</span> <span class=\"t-var\">$path</span>\n    <span class=\"t-kw\">if</span> (<span class=\"t-var\">$sig</span>.Status -ne <span class=\"t-str\">'Valid'</span>) {\n      Add-Finding <span class=\"t-str\">'UNSIGNED_PROC'</span> <span class=\"t-str\">'HIGH'</span> <span class=\"t-str\">\"$($_.Name) PID=$($_.Id)\"</span> @{\n        Path      = <span class=\"t-var\">$path</span>\n        SigStatus = <span class=\"t-var\">$sig</span>.Status\n        MD5       = (<span class=\"t-fn\">Get-FileHash</span> <span class=\"t-var\">$path</span> -Algorithm MD5).Hash\n      }\n    }\n  } <span class=\"t-kw\">catch</span> { <span class=\"t-cmt\"># Access denied for system procs — expected</span> }\n}\n\n<span class=\"t-cmt\"># ── 2. SUSPICIOUS PARENT-CHILD CHAINS ────────────</span>\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"`n[*] Checking process lineage...\"</span>\n<span class=\"t-var\">$suspicious</span> = @(\n  @{Parent=<span class=\"t-str\">'winword.exe'</span>;  Child=<span class=\"t-str\">'cmd.exe'</span>}\n  @{Parent=<span class=\"t-str\">'winword.exe'</span>;  Child=<span class=\"t-str\">'powershell.exe'</span>}\n  @{Parent=<span class=\"t-str\">'excel.exe'</span>;    Child=<span class=\"t-str\">'wscript.exe'</span>}\n  @{Parent=<span class=\"t-str\">'outlook.exe'</span>;  Child=<span class=\"t-str\">'cmd.exe'</span>}\n  @{Parent=<span class=\"t-str\">'explorer.exe'</span>; Child=<span class=\"t-str\">'svchost.exe'</span>}\n)\n<span class=\"t-var\">$procs</span> = <span class=\"t-fn\">Get-CimInstance</span> Win32_Process | <span class=\"t-fn\">Select-Object</span> Name, ProcessId, ParentProcessId, CommandLine\n<span class=\"t-kw\">foreach</span> (<span class=\"t-var\">$rule</span> <span class=\"t-kw\">in</span> <span class=\"t-var\">$suspicious</span>) {\n  <span class=\"t-var\">$parents</span> = <span class=\"t-var\">$procs</span> | <span class=\"t-fn\">Where-Object</span> { <span class=\"t-var\">$_</span>.Name -eq <span class=\"t-var\">$rule</span>.Parent }\n  <span class=\"t-kw\">foreach</span> (<span class=\"t-var\">$parent</span> <span class=\"t-kw\">in</span> <span class=\"t-var\">$parents</span>) {\n    <span class=\"t-var\">$children</span> = <span class=\"t-var\">$procs</span> | <span class=\"t-fn\">Where-Object</span> { <span class=\"t-var\">$_</span>.ParentProcessId -eq <span class=\"t-var\">$parent</span>.ProcessId -and <span class=\"t-var\">$_</span>.Name -eq <span class=\"t-var\">$rule</span>.Child }\n    <span class=\"t-kw\">foreach</span> (<span class=\"t-var\">$child</span> <span class=\"t-kw\">in</span> <span class=\"t-var\">$children</span>) {\n      Add-Finding <span class=\"t-str\">'PROC_CHAIN'</span> <span class=\"t-str\">'HIGH'</span> <span class=\"t-str\">\"$($rule.Parent) → $($rule.Child)\"</span> <span class=\"t-var\">$child</span>.CommandLine\n    }\n  }\n}\n\n<span class=\"t-cmt\"># ── 3. PERSISTENCE — REGISTRY RUN KEYS ───────────</span>\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"`n[*] Checking persistence mechanisms...\"</span>\n<span class=\"t-var\">$runKeys</span> = @(\n  <span class=\"t-str\">'HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\Run'</span>\n  <span class=\"t-str\">'HKLM:\\Software\\Microsoft\\Windows\\CurrentVersion\\Run'</span>\n  <span class=\"t-str\">'HKLM:\\Software\\Microsoft\\Windows\\CurrentVersion\\RunOnce'</span>\n)\n<span class=\"t-kw\">foreach</span> (<span class=\"t-var\">$key</span> <span class=\"t-kw\">in</span> <span class=\"t-var\">$runKeys</span>) {\n  <span class=\"t-kw\">if</span> (<span class=\"t-fn\">Test-Path</span> <span class=\"t-var\">$key</span>) {\n    <span class=\"t-fn\">Get-ItemProperty</span> <span class=\"t-var\">$key</span> | <span class=\"t-fn\">Select-Object</span> -Property * -ExcludeProperty PS* |\n      <span class=\"t-fn\">Get-Member</span> -MemberType NoteProperty | <span class=\"t-fn\">ForEach-Object</span> {\n        <span class=\"t-var\">$val</span> = (<span class=\"t-fn\">Get-ItemProperty</span> <span class=\"t-var\">$key</span>).(<span class=\"t-var\">$_</span>.Name)\n        Add-Finding <span class=\"t-str\">'PERSISTENCE'</span> <span class=\"t-str\">'MED'</span> <span class=\"t-str\">\"RunKey: $($_.Name)\"</span> @{Key=<span class=\"t-var\">$key</span>; Value=<span class=\"t-var\">$val</span>}\n      }\n  }\n}\n\n<span class=\"t-cmt\"># ── 4. ACTIVE NETWORK CONNECTIONS ─────────────────</span>\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"`n[*] Checking network connections...\"</span>\n<span class=\"t-fn\">Get-NetTCPConnection</span> -State Established | <span class=\"t-fn\">ForEach-Object</span> {\n  <span class=\"t-var\">$conn</span> = <span class=\"t-var\">$_</span>\n  <span class=\"t-var\">$proc</span> = <span class=\"t-fn\">Get-Process</span> -Id <span class=\"t-var\">$conn</span>.OwningProcess -ErrorAction SilentlyContinue\n  <span class=\"t-cmt\"># Flag non-browser processes with outbound connections</span>\n  <span class=\"t-kw\">if</span> (<span class=\"t-var\">$proc</span>.Name -notin @(<span class=\"t-str\">'chrome'</span>,<span class=\"t-str\">'firefox'</span>,<span class=\"t-str\">'msedge'</span>,<span class=\"t-str\">'svchost'</span>)) {\n    Add-Finding <span class=\"t-str\">'NETWORK'</span> <span class=\"t-str\">'MED'</span> <span class=\"t-str\">\"$($proc.Name) → $($conn.RemoteAddress):$($conn.RemotePort)\"</span> $null\n  }\n}\n\n<span class=\"t-cmt\"># ── OUTPUT ────────────────────────────────────────</span>\n<span class=\"t-var\">$outFile</span> = <span class=\"t-str\">\"ThreatHunt_$(Get-Date -Format yyyyMMdd_HHmmss).json\"</span>\n<span class=\"t-var\">$report</span> | <span class=\"t-fn\">ConvertTo-Json</span> -Depth <span class=\"t-num\">5</span> | <span class=\"t-fn\">Out-File</span> <span class=\"t-var\">$outFile</span>\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"`n[✓] Report: $outFile | Findings: $($report.Findings.Count)\"</span> -ForegroundColor Green</pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bp\">Process Chains</span><span class=\"badge bp\">Sig Check</span>\n      <span class=\"badge bp\">Registry</span><span class=\"badge bp\">Network</span><span class=\"badge bp\">JSON Report</span>\n    </div>\n  </div>\n\n  <!-- PowerShell Script 2: Event Log Hunt -->\n  <div class=\"card ca-p\">\n    <div class=\"card-label\">Script 07 — Event Log Analysis</div>\n    <div class=\"card-title\" style=\"color:var(--purple)\">Security Event Log Hunter</div>\n    <div class=\"card-body\">Query Windows Security, System, and PowerShell event logs for high-value forensic event IDs — logon failures, privilege use, service installs, and lateral movement indicators.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">Get-SecurityEvents.ps1</span>\n        <span class=\"code-pane-lang lang-pwsh\">PWSH</span>\n      </div>\n      <pre><span class=\"t-cmt\"># Get-SecurityEvents.ps1 — Query high-value Windows event IDs</span>\n<span class=\"t-kw\">param</span>(\n  [DateTime]<span class=\"t-var\">$StartTime</span> = (Get-Date).AddHours(-<span class=\"t-num\">24</span>),\n  [string]  <span class=\"t-var\">$ComputerName</span> = <span class=\"t-var\">$env:COMPUTERNAME</span>\n)\n\n<span class=\"t-cmt\"># High-value Security Event IDs</span>\n<span class=\"t-var\">$eventMap</span> = [ordered]@{\n  <span class=\"t-num\">4624</span> = <span class=\"t-str\">\"Successful Logon\"</span>\n  <span class=\"t-num\">4625</span> = <span class=\"t-str\">\"Failed Logon\"</span>\n  <span class=\"t-num\">4648</span> = <span class=\"t-str\">\"Logon with Explicit Credentials\"</span>\n  <span class=\"t-num\">4672</span> = <span class=\"t-str\">\"Special Privileges Assigned\"</span>\n  <span class=\"t-num\">4698</span> = <span class=\"t-str\">\"Scheduled Task Created\"</span>\n  <span class=\"t-num\">4702</span> = <span class=\"t-str\">\"Scheduled Task Modified\"</span>\n  <span class=\"t-num\">4720</span> = <span class=\"t-str\">\"User Account Created\"</span>\n  <span class=\"t-num\">4732</span> = <span class=\"t-str\">\"Member Added to Security Group\"</span>\n  <span class=\"t-num\">7045</span> = <span class=\"t-str\">\"New Service Installed\"</span>\n  <span class=\"t-num\">4104</span> = <span class=\"t-str\">\"PowerShell Script Block\"</span>\n}\n\n<span class=\"t-var\">$filterXml</span> = @\"\n&lt;QueryList&gt;\n  &lt;Query Id=<span class=\"t-str\">\"0\"</span>&gt;\n    &lt;Select Path=<span class=\"t-str\">\"Security\"</span>&gt;\n      *[System[EventID=4624 or EventID=4625 or EventID=4648 or\n               EventID=4672 or EventID=4698 or EventID=4720 or\n               EventID=4732]\n        and System[TimeCreated[@SystemTime &gt;= '<span class=\"t-var\">$($StartTime.ToUniversalTime().ToString(\"o\"))</span>']]]\n    &lt;/Select&gt;\n    &lt;Select Path=<span class=\"t-str\">\"System\"</span>&gt;\n      *[System[EventID=7045]]\n    &lt;/Select&gt;\n    &lt;Select Path=<span class=\"t-str\">\"Microsoft-Windows-PowerShell/Operational\"</span>&gt;\n      *[System[EventID=4104]]\n    &lt;/Select&gt;\n  &lt;/Query&gt;\n&lt;/QueryList&gt;\n<span class=\"t-str\">\"@</span>\n\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[*] Querying events since $StartTime on $ComputerName\"</span>\n\n<span class=\"t-fn\">Get-WinEvent</span> -FilterXml <span class=\"t-var\">$filterXml</span> -ComputerName <span class=\"t-var\">$ComputerName</span> -ErrorAction SilentlyContinue |\n  <span class=\"t-fn\">Sort-Object</span> TimeCreated |\n  <span class=\"t-fn\">Select-Object</span> TimeCreated, Id,\n    @{n=<span class=\"t-str\">'Description'</span>;e={<span class=\"t-var\">$eventMap</span>[[int]<span class=\"t-var\">$_</span>.Id] ?? <span class=\"t-str\">\"Event $($_.Id)\"</span>}},\n    Message |\n  <span class=\"t-fn\">Format-Table</span> -AutoSize |\n  <span class=\"t-fn\">Out-Host</span>\n\n<span class=\"t-cmt\"># Highlight failed logon bursts (brute force indicator)</span>\n<span class=\"t-var\">$failedLogons</span> = <span class=\"t-fn\">Get-WinEvent</span> -FilterXml <span class=\"t-var\">$filterXml</span> -ErrorAction SilentlyContinue |\n  <span class=\"t-fn\">Where-Object</span> { <span class=\"t-var\">$_</span>.Id -eq <span class=\"t-num\">4625</span> }\n<span class=\"t-kw\">if</span> (<span class=\"t-var\">$failedLogons</span>.Count -gt <span class=\"t-num\">20</span>) {\n  <span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[!] ALERT: $($failedLogons.Count) failed logons in last 24h\"</span> -ForegroundColor Red\n}</pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bp\">Event IDs</span><span class=\"badge bp\">XPath Filter</span>\n      <span class=\"badge bp\">Brute Force Alert</span><span class=\"badge bp\">Remote Query</span>\n    </div>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     MODULE: SECURE CODING\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-secure\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">04</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-tag\">// Secure Coding Patterns //</div>\n      <div class=\"sh-title\" style=\"color:var(--orange)\">Scripting Vulnerabilities & Defenses</div>\n      <div class=\"sh-desc\">Security scripts that are themselves insecure are ironic liabilities. Every pattern here is a real-world vulnerability class found in production security tooling.</div>\n    </div>\n  </div>\n\n  <div class=\"alert a-warn\">\n    <strong>Reality:</strong> Many production security scripts contain injection flaws, hardcoded credentials, race conditions, and TOCTOU bugs — creating attack surface within the blue team's own toolchain.\n  </div>\n\n  <!-- Vuln 1: Command Injection -->\n  <div class=\"card ca-o\" style=\"margin-bottom:16px\">\n    <div class=\"card-label\">Vulnerability 01</div>\n    <div class=\"card-title\" style=\"color:var(--orange)\">Command Injection — Bash & Python</div>\n    <div class=\"card-body\">The most common scripting flaw. Unsanitized user input passed to a shell command or <code>os.system()</code> allows arbitrary command execution.</div>\n    <div class=\"diff-block\">\n      <div class=\"diff-row diff-cmt\"><div class=\"diff-sign\"></div><div class=\"diff-code\">/* BASH — Command Injection */</div></div>\n      <div class=\"diff-row diff-rem\"><div class=\"diff-sign\">−</div><div class=\"diff-code\">user_input=\"$1\"\neval \"ls $user_input\"            # INJECTABLE: ; rm -rf /</div></div>\n      <div class=\"diff-row diff-rem\"><div class=\"diff-sign\">−</div><div class=\"diff-code\">grep \"$user_input\" /var/log/auth.log  # INJECTABLE</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">user_input=\"$1\"\n# Validate: only allow alphanumeric + dash + underscore\nif [[ ! \"$user_input\" =~ ^[a-zA-Z0-9_-]+$ ]]; then\n  echo \"Invalid input\" >&2; exit 1\nfi\nls -- \"$user_input\"              # SAFE: quoted + validated</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">grep -F \"$user_input\" /var/log/auth.log  # SAFE: -F = literal</div></div>\n      <div class=\"diff-row diff-cmt\"><div class=\"diff-sign\"></div><div class=\"diff-code\">/* PYTHON — shell=True danger */</div></div>\n      <div class=\"diff-row diff-rem\"><div class=\"diff-sign\">−</div><div class=\"diff-code\">import subprocess\nsubprocess.run(f\"ping {user_ip}\", shell=True)   # INJECTABLE</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">import subprocess, ipaddress\nipaddress.ip_address(user_ip)    # validate first — raises ValueError if bad\nsubprocess.run([\"ping\", \"-c1\", user_ip])        # SAFE: list, no shell</div></div>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bo\">CWE-78</span><span class=\"badge bo\">OS Command Injection</span><span class=\"badge bg\">Input Validation</span><span class=\"badge bg\">No shell=True</span>\n    </div>\n  </div>\n\n  <!-- Vuln 2: Hardcoded Credentials -->\n  <div class=\"card ca-o\" style=\"margin-bottom:16px\">\n    <div class=\"card-label\">Vulnerability 02</div>\n    <div class=\"card-title\" style=\"color:var(--orange)\">Credential Handling — All Languages</div>\n    <div class=\"card-body\">Hardcoded credentials in scripts committed to version control is one of the most common and costly security mistakes. Use environment variables or vaults.</div>\n    <div class=\"diff-block\">\n      <div class=\"diff-row diff-rem\"><div class=\"diff-sign\">−</div><div class=\"diff-code\">PASSWORD = \"admin123\"          # Python: hardcoded</div></div>\n      <div class=\"diff-row diff-rem\"><div class=\"diff-sign\">−</div><div class=\"diff-code\">$apiKey = \"sk-abc123...\"       # PowerShell: hardcoded</div></div>\n      <div class=\"diff-row diff-rem\"><div class=\"diff-sign\">−</div><div class=\"diff-code\">curl -u admin:password http:// # Bash: in command history</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">PASSWORD = os.environ[\"DB_PASSWORD\"]          # Python: env var</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">$apiKey = $env:API_KEY                        # PowerShell: env</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">password=$(vault kv get -field=pw secret/db)  # Bash: vault</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\"># Python: use keyring or secrets managers\nimport keyring\npassword = keyring.get_password(\"myapp\", \"dbuser\")</div></div>\n      <div class=\"diff-row diff-cmt\"><div class=\"diff-sign\"></div><div class=\"diff-code\">/* Also: add .env and *.sh to .gitignore; pre-commit hooks to scan */</div></div>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bo\">CWE-798</span><span class=\"badge bg\">Env Vars</span><span class=\"badge bg\">Vault</span><span class=\"badge bg\">Keyring</span>\n    </div>\n  </div>\n\n  <!-- Vuln 3: TOCTOU -->\n  <div class=\"card ca-o\" style=\"margin-bottom:16px\">\n    <div class=\"card-label\">Vulnerability 03</div>\n    <div class=\"card-title\" style=\"color:var(--orange)\">TOCTOU — Time-of-Check / Time-of-Use</div>\n    <div class=\"card-body\">A race condition where the state of a resource changes between checking it and using it. Common in temp file handling and file permission checks.</div>\n    <div class=\"diff-block\">\n      <div class=\"diff-row diff-cmt\"><div class=\"diff-sign\"></div><div class=\"diff-code\">/* BASH: temp file TOCTOU */</div></div>\n      <div class=\"diff-row diff-rem\"><div class=\"diff-sign\">−</div><div class=\"diff-code\">TMPFILE=\"/tmp/myscript_$$\"       # predictable path — symlink attack\necho \"data\" > $TMPFILE</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">TMPFILE=$(mktemp)                # random, secure temp file\ntrap 'rm -f \"$TMPFILE\"' EXIT    # always clean up via trap\necho \"data\" > \"$TMPFILE\"</div></div>\n      <div class=\"diff-row diff-cmt\"><div class=\"diff-sign\"></div><div class=\"diff-code\">/* PYTHON: file existence check TOCTOU */</div></div>\n      <div class=\"diff-row diff-rem\"><div class=\"diff-sign\">−</div><div class=\"diff-code\">if os.path.exists(path):        # file may disappear before open()\n    with open(path) as f: data = f.read()</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">try:                            # EAFP: Easier to Ask Forgiveness\n    with open(path) as f: data = f.read()\nexcept FileNotFoundError:\n    handle_missing()</div></div>\n      <div class=\"diff-row diff-cmt\"><div class=\"diff-sign\"></div><div class=\"diff-code\">/* PYTHON: atomic write to avoid partial reads */</div></div>\n      <div class=\"diff-row diff-add\"><div class=\"diff-sign\">+</div><div class=\"diff-code\">import tempfile, os\nwith tempfile.NamedTemporaryFile('w', dir=target_dir, delete=False) as f:\n    f.write(data)\n    tmp = f.name\nos.replace(tmp, target_path)    # atomic rename — readers see complete file</div></div>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge bo\">CWE-367</span><span class=\"badge bg\">mktemp</span><span class=\"badge bg\">Atomic Write</span><span class=\"badge bg\">EAFP</span>\n    </div>\n  </div>\n\n  <!-- Secure Coding Cheatsheet -->\n  <div class=\"card ca-o\">\n    <div class=\"card-label\">Reference — Security Checklist</div>\n    <div class=\"card-title\" style=\"color:var(--orange)\">Secure Scripting Checklist</div>\n    <table class=\"cmp-table\">\n      <tr>\n        <th>CHECK</th><th>BASH</th><th>PYTHON</th><th>PWSH</th>\n      </tr>\n      <tr>\n        <td><strong>Strict mode</strong></td>\n        <td class=\"td-g\">set -euo pipefail</td>\n        <td class=\"td-c\">No equivalent (use linting)</td>\n        <td class=\"td-p\">Set-StrictMode -Version Latest</td>\n      </tr>\n      <tr>\n        <td><strong>Input validation</strong></td>\n        <td class=\"td-g\">[[ $x =~ ^[a-z]+$ ]]</td>\n        <td class=\"td-c\">re.fullmatch() or schema validation</td>\n        <td class=\"td-p\">ValidatePattern attribute</td>\n      </tr>\n      <tr>\n        <td><strong>No shell=True</strong></td>\n        <td class=\"td-g\">Quote all variables</td>\n        <td class=\"td-c\">subprocess list args only</td>\n        <td class=\"td-p\">Avoid Invoke-Expression</td>\n      </tr>\n      <tr>\n        <td><strong>Credentials</strong></td>\n        <td class=\"td-g\">Env vars / vault</td>\n        <td class=\"td-c\">os.environ / keyring</td>\n        <td class=\"td-p\">$env: / SecureString</td>\n      </tr>\n      <tr>\n        <td><strong>Temp files</strong></td>\n        <td class=\"td-g\">mktemp + trap cleanup</td>\n        <td class=\"td-c\">tempfile.NamedTemporaryFile</td>\n        <td class=\"td-p\">New-TemporaryFile</td>\n      </tr>\n      <tr>\n        <td><strong>Least privilege</strong></td>\n        <td class=\"td-g\">Drop root ASAP</td>\n        <td class=\"td-c\">Run as non-root service</td>\n        <td class=\"td-p\">Use #Requires -RunAsAdmin sparingly</td>\n      </tr>\n      <tr>\n        <td><strong>Logging</strong></td>\n        <td class=\"td-g\">Structured with timestamps</td>\n        <td class=\"td-c\">logging module, not print()</td>\n        <td class=\"td-p\">Write-EventLog or structured</td>\n      </tr>\n    </table>\n  </div>\n\n</div>\n</div>\n\n<!-- ══════════════════════════════════\n     MODULE: INCIDENT RESPONSE\n══════════════════════════════════ -->\n<div class=\"module z1\" id=\"mod-ir\">\n<div class=\"wrapper\">\n\n  <div class=\"sh\">\n    <div class=\"sh-num\">05</div>\n    <div class=\"sh-body\">\n      <div class=\"sh-tag\">// Incident Response Automation //</div>\n      <div class=\"sh-title\" style=\"color:var(--red)\">IR Scripts & Playbooks</div>\n      <div class=\"sh-desc\">Time is the enemy during an incident. These scripts automate the first 15 minutes of triage — evidence preservation, network isolation decisions, and timeline reconstruction.</div>\n    </div>\n  </div>\n\n  <div class=\"flow\" style=\"margin-bottom:28px\">\n    <div class=\"flow-step\">\n      <div class=\"flow-num\">01</div><div class=\"flow-icon\">🚨</div>\n      <div class=\"flow-name\">DETECT</div><div class=\"flow-desc\">Alert fires or IOC identified</div>\n    </div>\n    <div class=\"flow-step\">\n      <div class=\"flow-num\">02</div><div class=\"flow-icon\">🔒</div>\n      <div class=\"flow-name\">CONTAIN</div><div class=\"flow-desc\">Isolate host / block network</div>\n    </div>\n    <div class=\"flow-step\">\n      <div class=\"flow-num\">03</div><div class=\"flow-icon\">📸</div>\n      <div class=\"flow-name\">PRESERVE</div><div class=\"flow-desc\">Memory dump, disk image, logs</div>\n    </div>\n    <div class=\"flow-step\">\n      <div class=\"flow-num\">04</div><div class=\"flow-icon\">🔬</div>\n      <div class=\"flow-name\">ANALYZE</div><div class=\"flow-desc\">Triage, IOC extraction, timeline</div>\n    </div>\n    <div class=\"flow-step\">\n      <div class=\"flow-num\">05</div><div class=\"flow-icon\">🧹</div>\n      <div class=\"flow-name\">ERADICATE</div><div class=\"flow-desc\">Remove malware, patch vuln</div>\n    </div>\n    <div class=\"flow-step\">\n      <div class=\"flow-num\">06</div><div class=\"flow-icon\">📋</div>\n      <div class=\"flow-name\">REPORT</div><div class=\"flow-desc\">Timeline, PIR, lessons learned</div>\n    </div>\n  </div>\n\n  <!-- IR Script 1: Linux Triage -->\n  <div class=\"card ca-r\" style=\"margin-bottom:16px\">\n    <div class=\"card-label\">Script 08 — Linux IR Triage</div>\n    <div class=\"card-title\" style=\"color:var(--red)\">Linux First-Responder Collection Script</div>\n    <div class=\"card-body\">Collects volatile evidence in order of volatility (memory state → running processes → network → disk artifacts). Designed to run within the first 5 minutes of a Linux incident.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">linux_triage.sh</span>\n        <span class=\"code-pane-lang lang-bash\">BASH</span>\n      </div>\n      <pre><span class=\"t-cmt\">#!/usr/bin/env bash\n# linux_triage.sh — First-responder evidence collection\n# MUST run as root. Collects volatile evidence before shutdown.\n# Output: timestamped tarball of all artifacts</span>\n\n<span class=\"t-kw\">set</span> -euo pipefail\n[[ <span class=\"t-var\">$EUID</span> -ne <span class=\"t-num\">0</span> ]] &amp;&amp; { <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"Run as root\"</span>; exit <span class=\"t-num\">1</span>; }\n\n<span class=\"t-var\">TS</span>=$(<span class=\"t-fn\">date</span> -u +%Y%m%d_%H%M%SZ)\n<span class=\"t-var\">HOST</span>=$(<span class=\"t-fn\">hostname</span> -s)\n<span class=\"t-var\">OUT</span>=<span class=\"t-str\">\"/tmp/triage_${HOST}_${TS}\"</span>\n<span class=\"t-fn\">mkdir</span> -p <span class=\"t-str\">\"$OUT\"</span>/{volatile,network,persist,logs}\n<span class=\"t-kw\">trap</span> <span class=\"t-str\">\"tar -czf ${OUT}.tar.gz -C /tmp triage_${HOST}_${TS} && rm -rf '$OUT' && echo '[✓] Package: ${OUT}.tar.gz'\"</span> EXIT\n\n<span class=\"t-fn\">log</span>() { <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"[$(date -u +%T)] $*\"</span>; }\n<span class=\"t-fn\">cap</span>() {\n  <span class=\"t-cmt\"># cap label command → saves output to file, handles errors</span>\n  <span class=\"t-kw\">local</span> label=<span class=\"t-str\">\"$1\"</span>; shift\n  log <span class=\"t-str\">\"Collecting: $label\"</span>\n  <span class=\"t-str\">\"$@\"</span> &gt; <span class=\"t-str\">\"$OUT/${label}.txt\"</span> <span class=\"t-num\">2</span>&gt;&amp;<span class=\"t-num\">1</span> <span class=\"t-op\">||</span> <span class=\"t-fn\">echo</span> <span class=\"t-str\">\"[WARN] $label failed\"</span>\n}\n\n<span class=\"t-cmt\"># ── PHASE 1: MOST VOLATILE FIRST ─────────────────</span>\nlog <span class=\"t-str\">\"=== PHASE 1: VOLATILE DATA ===\"</span>\ncap volatile/date           date -u\ncap volatile/uptime         uptime\ncap volatile/who            who -a\ncap volatile/last           last -n 50\ncap volatile/w              w\ncap volatile/ps_full        ps auxef --forest\ncap volatile/proc_environ   bash -c <span class=\"t-str\">'for p in /proc/[0-9]*/environ; do\n  pid=$(echo $p | cut -d/ -f3)\n  echo \"=== PID $pid ===\"; cat \"$p\" 2>/dev/null | tr \"\\0\" \"\\n\"; done'</span>\ncap volatile/lsof           lsof -nP\ncap volatile/fds            bash -c <span class=\"t-str\">'ls -la /proc/[0-9]*/fd 2>/dev/null | grep \"(deleted)\"'</span>\n\n<span class=\"t-cmt\"># ── PHASE 2: NETWORK ──────────────────────────────</span>\nlog <span class=\"t-str\">\"=== PHASE 2: NETWORK STATE ===\"</span>\ncap network/ss              ss -tnpua\ncap network/arp             arp -an\ncap network/routes          ip route show\ncap network/iptables        iptables -L -n -v\ncap network/dns_resolv      cat /etc/resolv.conf\ncap network/hosts           cat /etc/hosts\n\n<span class=\"t-cmt\"># ── PHASE 3: PERSISTENCE ──────────────────────────</span>\nlog <span class=\"t-str\">\"=== PHASE 3: PERSISTENCE MECHANISMS ===\"</span>\ncap persist/crontabs        bash -c <span class=\"t-str\">'for u in $(cut -d: -f1 /etc/passwd); do\n  echo \"=== $u ===\"; crontab -u \"$u\" -l 2>/dev/null; done'</span>\ncap persist/cron_dirs       find /etc/cron* /var/spool/cron -type f <span class=\"t-num\">2</span>&gt;/dev/null\ncap persist/services        systemctl list-units --type=service --all\ncap persist/timers          systemctl list-timers --all\ncap persist/startup_files   cat /etc/rc.local /etc/rc*.d/*.sh <span class=\"t-num\">2</span>&gt;/dev/null\ncap persist/ssh_keys        find /home /root -name <span class=\"t-str\">\"authorized_keys\"</span> -exec cat {} + <span class=\"t-num\">2</span>&gt;/dev/null\ncap persist/ld_preload      cat /etc/ld.so.preload <span class=\"t-num\">2</span>&gt;/dev/null\ncap persist/suid_files      find / -perm -4000 -type f <span class=\"t-num\">2</span>&gt;/dev/null\n\n<span class=\"t-cmt\"># ── PHASE 4: LOG COLLECTION ───────────────────────</span>\nlog <span class=\"t-str\">\"=== PHASE 4: LOG SNAPSHOTS ===\"</span>\n<span class=\"t-kw\">for</span> logfile <span class=\"t-kw\">in</span> auth.log syslog kern.log bash_history; <span class=\"t-kw\">do</span>\n  <span class=\"t-kw\">for</span> candidate <span class=\"t-kw\">in</span> /var/log/<span class=\"t-var\">$logfile</span> /home/*/.bash_history /root/.bash_history; <span class=\"t-kw\">do</span>\n    [[ -f <span class=\"t-str\">\"$candidate\"</span> ]] &amp;&amp; <span class=\"t-fn\">cp</span> <span class=\"t-str\">\"$candidate\"</span> <span class=\"t-str\">\"$OUT/logs/\"</span> <span class=\"t-num\">2</span>&gt;/dev/null <span class=\"t-op\">||</span> <span class=\"t-kw\">true</span>\n  <span class=\"t-kw\">done</span>\n<span class=\"t-kw\">done</span>\n\n<span class=\"t-cmt\"># ── PHASE 5: SYSTEM FINGERPRINT ──────────────────</span>\ncap volatile/uname          uname -a\ncap volatile/os_release     cat /etc/os-release\ncap volatile/installed_pkgs dpkg -l <span class=\"t-num\">2</span>&gt;/dev/null <span class=\"t-op\">||</span> rpm -qa <span class=\"t-num\">2</span>&gt;/dev/null\ncap volatile/recent_files   find / -newer /tmp -not -path <span class=\"t-str\">\"/proc/*\"</span> -not -path <span class=\"t-str\">\"/sys/*\"</span> \\\n                              -mmin -<span class=\"t-num\">60</span> -type f <span class=\"t-num\">2</span>&gt;/dev/null\n\nlog <span class=\"t-str\">\"Collection complete — packaging...\"</span></pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge br\">Volatility Order</span><span class=\"badge br\">Evidence Preservation</span>\n      <span class=\"badge br\">Auto-Package</span><span class=\"badge bg\">Error-Safe</span>\n    </div>\n  </div>\n\n  <!-- IR Script 2: Windows IR PowerShell -->\n  <div class=\"card ca-r\">\n    <div class=\"card-label\">Script 09 — Windows IR Containment</div>\n    <div class=\"card-title\" style=\"color:var(--red)\">Windows Network Isolation + Evidence Collection</div>\n    <div class=\"card-body\">Blocks all non-essential outbound traffic via Windows Firewall, preserves volatile state, and prepares a handoff package for forensic analysis — all reversible.</div>\n    <div class=\"code-pane\">\n      <div class=\"code-pane-bar\">\n        <span class=\"code-pane-name\">Invoke-IRContain.ps1</span>\n        <span class=\"code-pane-lang lang-pwsh\">PWSH</span>\n      </div>\n      <pre><span class=\"t-cmt\">#Requires -RunAsAdministrator\n<#\n.SYNOPSIS  Windows IR containment + volatile evidence collection\n.NOTES     -WhatIf supported for dry-run; -Undo reverses isolation\n#></span>\n<span class=\"t-kw\">param</span>([switch]<span class=\"t-var\">$Undo</span>, [switch]<span class=\"t-var\">$SkipIsolation</span>)\n\n<span class=\"t-var\">$TS</span>      = Get-Date -Format <span class=\"t-str\">\"yyyyMMdd_HHmmssZ\"</span>\n<span class=\"t-var\">$Host_</span>   = <span class=\"t-var\">$env:COMPUTERNAME</span>\n<span class=\"t-var\">$OutDir</span>  = <span class=\"t-str\">\"C:\\IR_${Host_}_${TS}\"</span>\n<span class=\"t-fn\">New-Item</span> -Path <span class=\"t-var\">$OutDir</span> -ItemType Directory -Force | Out-Null\n\n<span class=\"t-kw\">function</span> <span class=\"t-fn\">Save</span>(<span class=\"t-var\">$name</span>, <span class=\"t-var\">$data</span>) {\n  <span class=\"t-var\">$data</span> | <span class=\"t-fn\">Out-File</span> -FilePath <span class=\"t-str\">\"$OutDir\\$name.txt\"</span> -Encoding UTF8\n}\n\n<span class=\"t-cmt\"># ── VOLATILE EVIDENCE ─────────────────────────────</span>\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[*] Collecting volatile state...\"</span> -ForegroundColor Cyan\n\nSave <span class=\"t-str\">\"01_datetime\"</span>    (Get-Date -Format o)\nSave <span class=\"t-str\">\"02_processes\"</span>   (<span class=\"t-fn\">Get-CimInstance</span> Win32_Process |\n  <span class=\"t-fn\">Select-Object</span> Name, ProcessId, ParentProcessId,\n    CommandLine, ExecutablePath,\n    @{n=<span class=\"t-str\">'StartTime'</span>;e={<span class=\"t-var\">$_</span>.CreationDate}} |\n  <span class=\"t-fn\">Format-List</span>)\nSave <span class=\"t-str\">\"03_network\"</span>     (<span class=\"t-fn\">Get-NetTCPConnection</span> | <span class=\"t-fn\">Select-Object</span> LocalAddress, LocalPort,\n  RemoteAddress, RemotePort, State, OwningProcess | <span class=\"t-fn\">Format-Table</span>)\nSave <span class=\"t-str\">\"04_loggedon\"</span>    (<span class=\"t-fn\">Get-CimInstance</span> Win32_LoggedOnUser)\nSave <span class=\"t-str\">\"05_services\"</span>    (<span class=\"t-fn\">Get-Service</span> | <span class=\"t-fn\">Where-Object</span> {<span class=\"t-var\">$_</span>.Status -eq <span class=\"t-str\">'Running'</span>})\nSave <span class=\"t-str\">\"06_startup\"</span>     (<span class=\"t-fn\">Get-CimInstance</span> Win32_StartupCommand)\nSave <span class=\"t-str\">\"07_shares\"</span>      (<span class=\"t-fn\">Get-SmbShare</span>)\nSave <span class=\"t-str\">\"08_scheduled\"</span>   (<span class=\"t-fn\">Get-ScheduledTask</span> | <span class=\"t-fn\">Where-Object</span> State -ne <span class=\"t-str\">'Disabled'</span>)\nSave <span class=\"t-str\">\"09_run_keys\"</span>    (<span class=\"t-fn\">Get-ItemProperty</span> <span class=\"t-str\">'HKCU:\\Software\\Microsoft\\Windows\\CurrentVersion\\Run'</span>)\nSave <span class=\"t-str\">\"10_prefetch\"</span>    (<span class=\"t-fn\">Get-ChildItem</span> C:\\Windows\\Prefetch | <span class=\"t-fn\">Sort-Object</span> LastWriteTime -Descending | <span class=\"t-fn\">Select-Object</span> -First <span class=\"t-num\">50</span>)\n\n<span class=\"t-cmt\"># ── NETWORK ISOLATION ─────────────────────────────</span>\n<span class=\"t-kw\">if</span> (<span class=\"t-op\">-not</span> <span class=\"t-var\">$SkipIsolation</span> -and <span class=\"t-op\">-not</span> <span class=\"t-var\">$Undo</span>) {\n  <span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[!] Isolating host — blocking all outbound except RDP (3389)\"</span> -ForegroundColor Red\n  <span class=\"t-cmt\"># Block all outbound</span>\n  <span class=\"t-fn\">New-NetFirewallRule</span> -DisplayName <span class=\"t-str\">\"IR_BLOCK_OUTBOUND\"</span> `\n    -Direction Outbound -Action Block -Profile Any `\n    -Description <span class=\"t-str\">\"IR containment $(Get-Date -Format o)\"</span> | Out-Null\n  <span class=\"t-cmt\"># Allow RDP so responders can still connect</span>\n  <span class=\"t-fn\">New-NetFirewallRule</span> -DisplayName <span class=\"t-str\">\"IR_ALLOW_RDP\"</span> `\n    -Direction Outbound -Action Allow -Protocol TCP -RemotePort <span class=\"t-num\">3389</span> | Out-Null\n  <span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[✓] Host isolated. Run with -Undo to restore.\"</span> -ForegroundColor Yellow\n}\n\n<span class=\"t-kw\">if</span> (<span class=\"t-var\">$Undo</span>) {\n  <span class=\"t-fn\">Remove-NetFirewallRule</span> -DisplayName <span class=\"t-str\">\"IR_BLOCK_OUTBOUND\"</span> -ErrorAction SilentlyContinue\n  <span class=\"t-fn\">Remove-NetFirewallRule</span> -DisplayName <span class=\"t-str\">\"IR_ALLOW_RDP\"</span>    -ErrorAction SilentlyContinue\n  <span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[✓] Isolation rules removed — network restored\"</span> -ForegroundColor Green\n  exit <span class=\"t-num\">0</span>\n}\n\n<span class=\"t-cmt\"># ── PACKAGE ───────────────────────────────────────</span>\n<span class=\"t-fn\">Compress-Archive</span> -Path <span class=\"t-var\">$OutDir</span> -DestinationPath <span class=\"t-str\">\"${OutDir}.zip\"</span>\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[✓] Evidence package: ${OutDir}.zip\"</span> -ForegroundColor Green\n(<span class=\"t-fn\">Get-FileHash</span> <span class=\"t-str\">\"${OutDir}.zip\"</span>).Hash | <span class=\"t-fn\">Out-File</span> <span class=\"t-str\">\"${OutDir}.zip.sha256\"</span>\n<span class=\"t-fn\">Write-Host</span> <span class=\"t-str\">\"[✓] Hash: $(Get-Content \"${OutDir}.zip.sha256\")\"</span></pre>\n    </div>\n    <div class=\"badge-row\">\n      <span class=\"badge br\">Network Isolation</span><span class=\"badge br\">Reversible</span>\n      <span class=\"badge br\">Volatile First</span><span class=\"badge bg\">SHA-256 Hash</span><span class=\"badge bp\">-WhatIf Safe</span>\n    </div>\n  </div>\n\n  <div class=\"alert a-ok\" style=\"margin-top:20px\">\n    <strong>Next Module →</strong> Malware Fundamentals: taxonomy, infection chains, persistence mechanisms, and C2 communication models. Load the main platform for the full curriculum path.\n  </div>\n\n</div>\n</div>\n\n<script>\nfunction switchModule(id, btn) {\n  document.querySelectorAll('.module').forEach(m => m.classList.remove('active'));\n  document.querySelectorAll('.nav-pill').forEach(p => p.classList.remove('active'));\n  document.getElementById('mod-' + id).classList.add('active');\n  btn.classList.add('active');\n  window.scrollTo({ top: 0, behavior: 'smooth' });\n}\n</script>\n</body>\n</html>\n";

export default securityScriptingFundamentalsHtml;
